  1→/**
  2→ * Skills category view — fetches, displays, and manages CRUD for skills.
  3→ *
  4→ * Skills have: name (identity/filename) + content (markdown body).
  5→ * Name is read-only when editing (identity can't change); editable when adding.
  6→ */
  7→
  8→import { useState, useMemo, useCallback } from "react";
  9→import { Input } from "@/components/ui/input";
 10→import { Textarea } from "@/components/ui/textarea";
 11→import { Label } from "@/components/ui/label";
 12→import {
 13→  useAgentConfigList,
 14→  useSaveConfigItem,
 15→  useDeleteConfigItem,
 16→} from "../../api/agent-config.queries";
 17→import { CategoryContentArea } from "../CategoryContentArea";
 18→import { ConfigItemExpanded } from "../shared/ConfigItemExpanded";
 19→import { useCategoryCrud } from "../hooks/useCategoryCrud";
 20→import type { ConfigDisplayItem, ConfigScope, SkillItem } from "../../types";
 21→
 22→interface SkillsViewProps {
 23→  repoPath?: string;
 24→  repoName?: string;
 25→}
 26→
 27→function toDisplayItems(items: SkillItem[], scope: ConfigScope): ConfigDisplayItem[] {
 28→  return items.map((item) => ({
 29→    id: item.name,
 30→    name: item.name,
 31→    description: item.description,
 32→    scope,
 33→    category: "skills" as const,
 34→    raw: item,
 35→  }));
 36→}
 37→
 38→export function SkillsView({ repoPath, repoName }: SkillsViewProps) {
 39→  const globalQuery = useAgentConfigList<SkillItem[]>("skills", "global");
 40→  const projectQuery = useAgentConfigList<SkillItem[]>("skills", "project", repoPath, {
 41→    enabled: !!repoPath,
 42→  });
 43→
 44→  const globalItems = useMemo(
 45→    () => toDisplayItems(globalQuery.data ?? [], "global"),
 46→    [globalQuery.data]
 47→  );
 48→  const projectItems = useMemo(
 49→    () => toDisplayItems(projectQuery.data ?? [], "project"),
 50→    [projectQuery.data]
 51→  );
 52→  const isLoading = globalQuery.isLoading || (!!repoPath && projectQuery.isLoading);
 53→
 54→  const saveMutation = useSaveConfigItem("skills");
 55→  const deleteMutation = useDeleteConfigItem("skills");
 56→
 57→  const [formName, setFormName] = useState("");
 58→  const [formContent, setFormContent] = useState("");
 59→
 60→  const resetForm = useCallback(() => {
 61→    setFormName("");
 62→    setFormContent("");
 63→  }, []);
 64→
 65→  const populateForm = useCallback((raw: unknown) => {
 66→    const item = raw as SkillItem;
 67→    setFormName(item.name);
 68→    setFormContent(item.content);
 69→  }, []);
 70→
 71→  const crud = useCategoryCrud({ resetForm, populateForm });
 72→
 73→  const handleSave = useCallback(
 74→    (originalItem: ConfigDisplayItem | null) => {
 75→      if (!formName.trim()) return;
 76→      const scope = originalItem?.scope ?? crud.addingInScope ?? "global";
 77→      saveMutation.mutate(
 78→        {
 79→          data: { name: formName.trim(), content: formContent },
 80→          scope,
 81→          repoPath: scope === "project" ? repoPath : undefined,
 82→        },
 83→        { onSuccess: crud.clearEditing }
 84→      );
 85→    },
 86→    [formName, formContent, crud, repoPath, saveMutation]
 87→  );
 88→
 89→  const handleConfirmDelete = useCallback(() => {
 90→    if (!crud.pendingDelete) return;
 91→    deleteMutation.mutate(
 92→      {
 93→        id: crud.pendingDelete.id,
 94→        scope: crud.pendingDelete.scope,
 95→        repoPath: crud.pendingDelete.scope === "project" ? repoPath : undefined,
 96→      },
 97→      { onSettled: () => crud.setPendingDelete(null) }
 98→    );
