  1→/**
  2→ * Hooks category view — fetches, displays, and manages CRUD for hook configurations.
  3→ *
  4→ * Hooks are stored as { [eventName]: matcherGroup[] } in settings.json.
  5→ * Each matcher group: { matcher: string, hooks: Array<{ type, command, timeout? }> }
  6→ * The save endpoint expects the full hooks object — add/edit/delete rebuild
  7→ * the complete map and POST it.
  8→ *
  9→ * Display: summarizes commands inline (e.g. "→ setup.sh (10s)" instead of "1 handler").
 10→ * Editor: structured form with matcher pattern, command rows, and timeout fields.
 11→ */
 12→
 13→import { useState, useMemo, useCallback } from "react";
 14→import { Plus, X } from "lucide-react";
 15→import { Input } from "@/components/ui/input";
 16→import { Label } from "@/components/ui/label";
 17→import { Button } from "@/components/ui/button";
 18→import {
 19→  Select,
 20→  SelectContent,
 21→  SelectGroup,
 22→  SelectItem,
 23→  SelectLabel,
 24→  SelectTrigger,
 25→  SelectValue,
 26→} from "@/components/ui/select";
 27→import { useAgentConfigList, useSaveConfigItem } from "../../api/agent-config.queries";
 28→import { CategoryContentArea } from "../CategoryContentArea";
 29→import { ConfigItemExpanded } from "../shared/ConfigItemExpanded";
 30→import { useCategoryCrud } from "../hooks/useCategoryCrud";
 31→import type { ConfigDisplayItem, ConfigScope } from "../../types";
 32→
 33→/* ------------------------------------------------------------------ */
 34→/*  Types                                                               */
 35→/* ------------------------------------------------------------------ */
 36→
 37→interface FormCommand {
 38→  command: string;
 39→  timeout: string;
 40→}
 41→
 42→interface FormMatcherGroup {
 43→  matcher: string;
 44→  commands: FormCommand[];
 45→}
 46→
 47→interface HooksViewProps {
 48→  repoPath?: string;
 49→  repoName?: string;
 50→}
 51→
 52→/* ------------------------------------------------------------------ */
 53→/*  Helpers                                                             */
 54→/* ------------------------------------------------------------------ */
 55→
 56→/** Summarize hook handlers into a human-readable description line */
 57→function summarizeHandlers(handlers: unknown): string {
 58→  if (!Array.isArray(handlers) || handlers.length === 0) return "No handlers";
 59→
 60→  type MatcherGroup = { matcher?: string; hooks?: Array<{ command?: string; timeout?: number }> };
 61→  const groups = handlers as MatcherGroup[];
 62→  const totalCommands = groups.reduce((n, g) => n + (g.hooks?.length ?? 0), 0);
 63→
 64→  if (totalCommands === 0) return "No commands";
 65→
 66→  // Multiple matcher groups — show aggregate
 67→  if (groups.length > 1) {
 68→    return `${groups.length} groups, ${totalCommands} command${totalCommands !== 1 ? "s" : ""}`;
 69→  }
 70→
 71→  // Single group — show first command details
 72→  const group = groups[0];
 73→  const first = group.hooks?.[0];
 74→  if (!first?.command) return `${totalCommands} command${totalCommands !== 1 ? "s" : ""}`;
 75→
 76→  const basename = first.command.split("/").pop() ?? first.command;
 77→  const matcher = group.matcher ? `${group.matcher} → ` : "→ ";
 78→  const timeout = first.timeout ? ` (${first.timeout}s)` : "";
 79→  const suffix = totalCommands > 1 ? ` +${totalCommands - 1} more` : "";
 80→
 81→  return `${matcher}${basename}${timeout}${suffix}`;
 82→}
 83→
 84→function hooksToDisplayItems(
 85→  hooks: Record<string, unknown> | undefined,
 86→  scope: ConfigScope
 87→): ConfigDisplayItem[] {
 88→  if (!hooks || typeof hooks !== "object") return [];
 89→  return Object.entries(hooks).map(([event, handlers]) => ({
 90→    id: event,
 91→    name: event,
 92→    description: summarizeHandlers(handlers),
 93→    scope,
 94→    category: "hooks" as const,
 95→    raw: { event, handlers },
 96→  }));
 97→}
 98→
 99→/** Convert raw handlers to structured form state */
100→function handlersToFormGroups(handlers: unknown): FormMatcherGroup[] {
101→  if (!Array.isArray(handlers) || handlers.length === 0) {
102→    return [{ matcher: "", commands: [{ command: "", timeout: "" }] }];
103→  }
104→
105→  return handlers.map(
106→    (h: { matcher?: string; hooks?: Array<{ command?: string; timeout?: number }> }) => ({
107→      matcher: h.matcher ?? "",
108→      commands:
109→        Array.isArray(h.hooks) && h.hooks.length > 0
110→          ? h.hooks.map((cmd) => ({
111→              command: cmd.command ?? "",
112→              timeout: cmd.timeout != null ? String(cmd.timeout) : "",
113→            }))
114→          : [{ command: "", timeout: "" }],
115→    })
116→  );
117→}
118→
119→/** Convert form state back to API format */
120→function formGroupsToHandlers(groups: FormMatcherGroup[]) {
121→  return groups
122→    .map((g) => ({
123→      matcher: g.matcher,
124→      hooks: g.commands
125→        .filter((c) => c.command.trim())
126→        .map((c) => ({
127→          type: "command" as const,
128→          command: c.command.trim(),
129→          ...(c.timeout.trim() && !isNaN(Number(c.timeout)) ? { timeout: Number(c.timeout) } : {}),
130→        })),
131→    }))
132→    .filter((g) => g.hooks.length > 0);
133→}
134→
135→function createEmptyGroups(): FormMatcherGroup[] {
136→  return [{ matcher: "", commands: [{ command: "", timeout: "" }] }];
137→}
138→
139→/** Known Claude Code hook events with descriptions and matcher hints */
140→interface HookEventDef {
141→  value: string;
142→  desc: string;
143→  matcher?: string;
144→}
145→
146→const HOOK_EVENTS: { group: string; items: HookEventDef[] }[] = [
147→  {
148→    group: "Session",
149→    items: [
150→      { value: "SessionStart", desc: "Fires when a session begins" },
151→      { value: "SessionEnd", desc: "Fires when a session ends" },
152→      { value: "Stop", desc: "Fires when the agent stops" },
153→    ],
154→  },
155→  {
156→    group: "User",
157→    items: [
158→      { value: "UserPromptSubmit", desc: "Fires when user sends a message" },
159→      { value: "Notification", desc: "Fires on desktop notifications" },
160→    ],
161→  },
162→  {
163→    group: "Tools",
164→    items: [
165→      { value: "PreToolUse", desc: "Before a tool executes", matcher: "tool name" },
166→      { value: "PostToolUse", desc: "After a tool executes", matcher: "tool name" },
167→      { value: "PostToolUseFailure", desc: "After a tool fails", matcher: "tool name" },
168→      { value: "PermissionRequest", desc: "When a tool requests permission", matcher: "tool name" },
169→    ],
170→  },
171→  {
172→    group: "Agents",
173→    items: [
174→      { value: "SubagentStart", desc: "When a sub-agent spawns", matcher: "agent type" },
175→      { value: "SubagentStop", desc: "When a sub-agent finishes", matcher: "agent type" },
176→      { value: "TeammateIdle", desc: "When a teammate goes idle" },
177→      { value: "TaskCompleted", desc: "When a task completes" },
178→    ],
179→  },
180→  {
181→    group: "System",
182→    items: [
183→      { value: "ConfigChange", desc: "When config files change", matcher: "config source" },
184→      { value: "PreCompact", desc: "Before context compaction" },
185→      { value: "WorktreeCreate", desc: "When a git worktree is created" },
186→      { value: "WorktreeRemove", desc: "When a git worktree is removed" },
187→    ],
188→  },
189→];
190→
191→/** Return a contextual placeholder for the matcher input based on event type */
192→function getMatcherHint(event: string): string {
193→  const all = HOOK_EVENTS.flatMap((g) => g.items);
194→  const found = all.find((e) => e.value === event);
195→  if (found && "matcher" in found) return `Match by ${found.matcher} (empty = always)`;
196→  return "Pattern (empty = always match)";
