349→                    </SelectGroup>
350→                  ))}
351→                </SelectContent>
352→              </Select>
353→            </div>
354→          ) : (
355→            <p className="text-muted-foreground text-xs font-medium">{formEvent}</p>
356→          )}
357→
358→          {formGroups.map((group, gi) => (
359→            <div
360→              key={gi}
361→              className="border-border/30 bg-background/50 space-y-2 rounded-md border p-3"
362→            >
363→              <div className="flex items-center justify-between">
364→                <span className="text-muted-foreground text-2xs font-medium tracking-wide uppercase">
365→                  {formGroups.length > 1 ? `Matcher group ${gi + 1}` : "Matcher"}
366→                </span>
367→                {formGroups.length > 1 && (
368→                  <Button
369→                    variant="ghost"
370→                    size="icon"
371→                    className="text-muted-foreground h-5 w-5"
372→                    onClick={() => removeGroup(gi)}
