                        variant="ghost"
                        size="icon"
                        className="text-muted-foreground h-6 w-6 shrink-0"
                        onClick={() => removeCommand(gi, ci)}
                        aria-label="Remove command"
                      >
                        <X className="h-3 w-3" />
                      </Button>
                    )}
                  </div>
                ))}
                <Button
                  variant="ghost"
                  size="sm"
                  className="text-muted-foreground h-6 gap-1 px-2 text-xs"
                  onClick={() => addCommand(gi)}
                >
                  <Plus className="h-3 w-3" />
                  Add command
                </Button>
              </div>
            </div>
          ))}

          <Button
            variant="ghost"
            size="sm"
            className="text-muted-foreground h-6 gap-1 px-2 text-xs"
            onClick={addGroup}
          >
            <Plus className="h-3 w-3" />
            Add matcher group
          </Button>
        </ConfigItemExpanded>
      );
    },
    [
      formEvent,
      formGroups,
      handleSave,
      crud,
      saveMutation.isPending,
      updateGroupMatcher,
      updateCommand,
      addCommand,
      removeCommand,
      addGroup,
      removeGroup,
    ]
  );

  return (
    <CategoryContentArea
      categoryLabel="Hooks"
      globalItems={globalItems}
      projectItems={projectItems}
      repoName={repoName}
      repoPath={repoPath}
      isLoading={isLoading}
      onAdd={crud.handleAdd}
      onEdit={crud.handleEdit}
      onDelete={crud.handleDelete}
      editingItem={crud.editingItem}
      addingInScope={crud.addingInScope}
      renderEditForm={renderEditForm}
      pendingDeleteItem={crud.pendingDelete}
      onUndoDelete={crud.handleUndoDelete}
      onConfirmDelete={handleConfirmDelete}
    />
  );
}

