  1→import fs from 'fs';
  2→import path from 'path';
  3→import os from 'os';
  4→import { McpConfigFile, AgentConfigFile, SettingsFile } from '../lib/schemas';
  5→
  6→const CLAUDE_DIR = path.join(os.homedir(), '.claude');
  7→const COMMANDS_DIR = path.join(CLAUDE_DIR, 'commands');
  8→const AGENTS_DIR = path.join(CLAUDE_DIR, 'agents');
  9→const SETTINGS_PATH = path.join(CLAUDE_DIR, 'settings.json');
 10→
 11→/**
 12→ * Resolve the .claude directory for a given scope.
 13→ * Global: ~/.claude/    Project: {projectPath}/.claude/
 14→ * Validates that projectPath is an absolute path to prevent traversal attacks.
 15→ */
 16→export function resolveClaudeDir(projectPath?: string): string {
 17→  if (!projectPath) return CLAUDE_DIR;
 18→  if (!path.isAbsolute(projectPath)) {
 19→    throw new Error('projectPath must be an absolute path');
 20→  }
 21→  return path.join(projectPath, '.claude');
 22→}
 23→
 24→function sanitizeName(name: string): string {
 25→  if (!name || !/^[a-zA-Z0-9_-]+$/.test(name)) {
 26→    throw new Error('Invalid name: must be alphanumeric, hyphens, or underscores only');
 27→  }
 28→  return name;
 29→}
 30→
 31→function ensureDirectories(): void {
 32→  const dirs = [CLAUDE_DIR, path.join(CLAUDE_DIR, 'plugins'), COMMANDS_DIR, AGENTS_DIR];
 33→  dirs.forEach(dir => {
 34→    if (!fs.existsSync(dir)) {
 35→      fs.mkdirSync(dir, { recursive: true });
 36→    }
 37→  });
 38→}
 39→
 40→// Initialize global directories on module load
 41→ensureDirectories();
 42→
 43→// ============================================================================
 44→// MCP Servers
 45→// ============================================================================
 46→
 47→export function getMcpServers(projectPath?: string): Array<{ name: string; command: string; args: string[]; env: Record<string, string> }> {
 48→  const configPath = path.join(resolveClaudeDir(projectPath), 'plugins', 'config.json');
 49→  if (!fs.existsSync(configPath)) return [];
 50→
 51→  let raw: unknown;
 52→  try {
 53→    raw = JSON.parse(fs.readFileSync(configPath, 'utf8'));
 54→  } catch {
 55→    console.error('Failed to parse MCP config file as JSON');
 56→    return [];
 57→  }
 58→
 59→  const parsed = McpConfigFile.safeParse(raw);
 60→  if (!parsed.success) {
 61→    console.error('Invalid MCP config file:', parsed.error.issues);
 62→    return [];
 63→  }
 64→
 65→  return Object.entries(parsed.data.mcpServers).map(([name, entry]) => ({
 66→    name,
 67→    command: entry.command,
 68→    args: entry.args,
 69→    env: entry.env,
 70→  }));
 71→}
 72→
 73→export function saveMcpServers(servers: Array<{ name: string; command: string; args?: string[]; env?: Record<string, string> }>, projectPath?: string): void {
 74→  const configPath = path.join(resolveClaudeDir(projectPath), 'plugins', 'config.json');
 75→  const configDir = path.dirname(configPath);
 76→  if (!fs.existsSync(configDir)) {
 77→    fs.mkdirSync(configDir, { recursive: true });
 78→  }
 79→
 80→  // Read existing config to preserve non-mcpServers keys
 81→  let existing: Record<string, unknown> = {};
 82→  if (fs.existsSync(configPath)) {
 83→    try {
 84→      const parsed = JSON.parse(fs.readFileSync(configPath, 'utf8'));
 85→      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
 86→        existing = parsed as Record<string, unknown>;
 87→      }
 88→    } catch {
 89→      // Corrupted config — start fresh
 90→      console.error('Failed to parse existing MCP config, starting fresh');
 91→    }
 92→  }
 93→
 94→  const mcpServers: Record<string, { command: string; args: string[]; env: Record<string, string> }> = {};
 95→  servers.forEach(server => {
 96→    mcpServers[server.name] = {
 97→      command: server.command,
 98→      args: server.args || [],
 99→      env: server.env || {},
100→    };
101→  });
102→
103→  fs.writeFileSync(configPath, JSON.stringify({ ...existing, mcpServers }, null, 2));
104→}
105→
106→// ============================================================================
107→// Commands
108→// ============================================================================
109→
110→export function getCommands(projectPath?: string): Array<{ name: string; description: string; content: string }> {
111→  const commandsDir = path.join(resolveClaudeDir(projectPath), 'commands');
112→  if (!fs.existsSync(commandsDir)) return [];
113→
114→  const files = fs.readdirSync(commandsDir).filter(f => f.endsWith('.md'));
115→  const commands: Array<{ name: string; description: string; content: string }> = [];
116→
117→  files.forEach(file => {
118→    const filePath = path.join(commandsDir, file);
119→    const content = fs.readFileSync(filePath, 'utf8');
120→    const name = file.replace('.md', '');
121→    const firstLine = content.split('\n')[0];
122→    const description = firstLine.replace(/^#\s*/, '');
123→    commands.push({ name, description, content });
124→  });
125→
126→  return commands;
127→}
128→
129→export function saveCommand(name: string, content: string, projectPath?: string): void {
130→  name = sanitizeName(name);
131→  const commandsDir = path.join(resolveClaudeDir(projectPath), 'commands');
132→  if (!fs.existsSync(commandsDir)) {
133→    fs.mkdirSync(commandsDir, { recursive: true });
134→  }
135→  const filePath = path.join(commandsDir, `${name}.md`);
136→  fs.writeFileSync(filePath, content);
137→}
138→
139→export function deleteCommand(name: string, projectPath?: string): boolean {
140→  name = sanitizeName(name);
141→  const filePath = path.join(resolveClaudeDir(projectPath), 'commands', `${name}.md`);
142→  if (fs.existsSync(filePath)) {
143→    fs.unlinkSync(filePath);
144→    return true;
145→  }
146→  return false;
147→}
148→
149→// ============================================================================
150→// Agents
151→// ============================================================================
152→
153→export function getAgents(projectPath?: string): Array<{ id: string; name?: string; description?: string; tools?: string[] }> {
154→  const agentsDir = path.join(resolveClaudeDir(projectPath), 'agents');
155→  if (!fs.existsSync(agentsDir)) return [];
156→
157→  const files = fs.readdirSync(agentsDir).filter(f => f.endsWith('.json'));
158→  const agents: Array<{ id: string; name?: string; description?: string; tools?: string[] }> = [];
159→
160→  files.forEach(file => {
161→    const filePath = path.join(agentsDir, file);
162→    try {
163→      const raw = JSON.parse(fs.readFileSync(filePath, 'utf8'));
164→      const parsed = AgentConfigFile.safeParse(raw);
165→      if (!parsed.success) {
166→        console.error(`Invalid agent config ${file}:`, parsed.error.issues);
167→        return;
168→      }
169→      agents.push({ ...parsed.data, id: file.replace('.json', '') });
170→    } catch {
171→      // Skip unparseable agent files — they may be hand-edited
172→      console.error(`Failed to parse agent file: ${file}`);
173→    }
174→  });
175→
176→  return agents;
177→}
178→
179→export function saveAgent(id: string, agentData: { name?: string; description?: string; tools?: string[] }, projectPath?: string): void {
180→  id = sanitizeName(id);
181→  const agentsDir = path.join(resolveClaudeDir(projectPath), 'agents');
182→  if (!fs.existsSync(agentsDir)) {
183→    fs.mkdirSync(agentsDir, { recursive: true });
184→  }
185→  const filePath = path.join(agentsDir, `${id}.json`);
186→  fs.writeFileSync(filePath, JSON.stringify(agentData, null, 2));
187→}
188→
189→export function deleteAgent(id: string, projectPath?: string): boolean {
190→  id = sanitizeName(id);
191→  const filePath = path.join(resolveClaudeDir(projectPath), 'agents', `${id}.json`);
192→  if (fs.existsSync(filePath)) {
193→    fs.unlinkSync(filePath);
194→    return true;
195→  }
196→  return false;
197→}
198→
199→// ============================================================================
200→// Hooks
201→// ============================================================================
202→
203→export function getHooks(projectPath?: string): Record<string, unknown> {
204→  const settingsPath = path.join(resolveClaudeDir(projectPath), 'settings.json');
205→  if (!fs.existsSync(settingsPath)) return {};
206→
207→  let raw: unknown;
208→  try {
209→    raw = JSON.parse(fs.readFileSync(settingsPath, 'utf8'));
210→  } catch {
211→    console.error('Failed to parse settings.json as JSON');
212→    return {};
213→  }
214→
215→  const parsed = SettingsFile.safeParse(raw);
216→  if (!parsed.success) {
217→    console.error('Invalid settings file:', parsed.error.issues);
218→    return {};
219→  }
220→  return parsed.data.hooks;
221→}
222→
223→export function saveHooks(hooks: Record<string, unknown>, projectPath?: string): void {
224→  const settingsPath = path.join(resolveClaudeDir(projectPath), 'settings.json');
225→  let settings: Record<string, unknown> = {};
226→  if (fs.existsSync(settingsPath)) {
227→    try {
228→      const parsed = JSON.parse(fs.readFileSync(settingsPath, 'utf8'));
229→      // Only use parsed result if it's a plain object — arrays, strings, etc. are not valid settings
230→      if (parsed && typeof parsed === 'object' && !Array.isArray(parsed)) {
231→        settings = parsed as Record<string, unknown>;
232→      } else {
233→        console.error('settings.json is not a valid object, starting with empty settings');
234→      }
235→    } catch {
236→      // Corrupted settings.json — start fresh to avoid crashing the write
237→      console.error('Failed to parse settings.json, starting with empty settings');
238→    }
239→  }
240→  settings.hooks = hooks;
241→  const settingsDir = path.dirname(settingsPath);
242→  if (!fs.existsSync(settingsDir)) {
243→    fs.mkdirSync(settingsDir, { recursive: true });
244→  }
245→  fs.writeFileSync(settingsPath, JSON.stringify(settings, null, 2));
246→}
247→
248→// ============================================================================
249→// Skills
250→// ============================================================================
