  1→export interface ConsoleLog {
  2→  timestamp: Date;
  3→  level: "info" | "warn" | "error" | "debug";
  4→  message: string;
  5→}
  6→
  7→/** Lightweight tab state persisted in the workspace layout store.
  8→ *  Only what's needed to restore a tab — webviews are destroyed/recreated. */
  9→export interface PersistedBrowserTab {
 10→  id: string;
 11→  url: string; // last loaded URL
 12→  title: string; // display title
 13→}
 14→
 15→export interface BrowserTabState {
 16→  id: string;
 17→  /** Unique label for the native Tauri webview instance */
 18→  webviewLabel: string;
 19→  /** Display title: auto-derived from URL domain, overridden by native title events */
 20→  title: string;
 21→  /** Value in URL input bar */
 22→  url: string;
 23→  /** Currently loaded URL in the webview */
 24→  currentUrl: string;
 25→  /** Navigation history stack */
 26→  history: string[];
 27→  /** Current position in history */
 28→  historyIndex: number;
 29→  /** Whether iframe is loading */
 30→  loading: boolean;
 31→  /** Error message if page load failed */
 32→  error: string | null;
 33→  /** Whether automation script has been injected */
 34→  injected: boolean;
 35→  /** Whether automation injection failed (shown as error indicator) */
 36→  injectionFailed: boolean;
 37→  /** Whether element selector mode is active */
 38→  selectorActive: boolean;
 39→  /** Whether DevTools inspector is docked (stolen NSView in main window) */
 40→  devtoolsOpen: boolean;
 41→  /** Console logs for this tab */
 42→  consoleLogs: ConsoleLog[];
 43→}
 44→
 45→/** Data emitted when user selects an element in inspect mode */
 46→export interface ElementSelectedEvent {
 47→  type: "element-selected" | "area-selected";
 48→  ref?: string;
 49→  /** "local" = own dev server (localhost), "external" = any other website */
 50→  context?: "local" | "external";
 51→  element?: {
 52→    tagName: string;
 53→    id?: string;
 54→    className?: string;
 55→    innerText?: string;
 56→    path: string;
 57→    rect: { top: number; left: number; width: number; height: number };
 58→    /** Context-aware CSS: var() tokens for local, visual props for external */
 59→    styles: Record<string, string>;
 60→    /** Serialized React props — primitives only (variant, size, disabled, etc.) */
 61→    props?: Record<string, string>;
 62→    /** Whitelisted HTML attributes (data-testid, href, type, role, aria-label, etc.) */
 63→    attributes?: Record<string, string>;
 64→    /** Shallow innerHTML capped at 500 chars — shows element structure */
 65→    innerHTML?: string;
 66→  };
 67→  reactComponent?: {
 68→    name: string;
 69→    fileName: string | null;
 70→    lineNumber: number | null;
 71→  };
 72→  bounds?: { x: number; y: number; width: number; height: number };
 73→  url: string;
 74→  timestamp: number;
 75→}
 76→
 77→/** Imperative methods exposed by BrowserTab via forwardRef */
 78→export interface BrowserTabHandle {
 79→  navigateToUrl: (url: string) => void;
 80→  reload: () => void;
 81→  injectAutomation: () => Promise<void>;
 82→  toggleElementSelector: () => void;
 83→  /** Force re-sync native webview position to placeholder bounds.
 84→   *  Call when the container layout shifts without a size change
 85→   *  (e.g., mobile view toggle repositions via flex centering). */
 86→  syncBounds: () => void;
 87→}
 88→
 89→/** Extract a readable title from a URL (domain or localhost:port) */
 90→export function deriveTitleFromUrl(url: string): string {
 91→  if (!url) return "New Tab";
 92→  try {
 93→    const parsed = new URL(url);
 94→    if (parsed.hostname === "localhost") {
 95→      return `localhost${parsed.port ? ":" + parsed.port : ""}`;
 96→    }
 97→    return parsed.hostname.replace(/^www\./, "");
 98→  } catch {
 99→    return "New Tab";
100→  }
101→}
102→
103→/** Create a fresh browser tab with default state.
104→ *  When workspaceId is provided, scopes the webview label to prevent
105→ *  collisions across workspaces. */
106→export function createBrowserTab(workspaceId?: string | null): BrowserTabState {
107→  const rand = Math.random().toString(36).slice(2, 6);
108→  const id = workspaceId
109→    ? `ws-${workspaceId.slice(0, 8)}-tab-${Date.now()}-${rand}`
110→    : `browser-tab-${Date.now()}-${rand}`;
111→  return {
112→    id,
113→    webviewLabel: id,
114→    title: "New Tab",
115→    url: "",
116→    currentUrl: "",
117→    history: [],
118→    historyIndex: -1,
119→    loading: false,
120→    error: null,
121→    injected: false,
122→    injectionFailed: false,
123→    selectorActive: false,
124→    devtoolsOpen: false,
125→    consoleLogs: [],
126→  };
127→}
128→
129→/** Hydrate a PersistedBrowserTab into a full BrowserTabState with
130→ *  ephemeral defaults (loading, history, consoleLogs, etc.) */
131→export function hydratePersistedTab(
132→  persisted: PersistedBrowserTab,
133→  workspaceId?: string | null
134→): BrowserTabState {
135→  const rand = Math.random().toString(36).slice(2, 6);
136→  // Create a new webview label (old webview is destroyed, new one will be created)
137→  const webviewLabel = workspaceId
138→    ? `ws-${workspaceId.slice(0, 8)}-tab-${Date.now()}-${rand}`
139→    : `browser-tab-${Date.now()}-${rand}`;
140→  return {
141→    id: persisted.id,
142→    webviewLabel,
143→    title: persisted.title || deriveTitleFromUrl(persisted.url),
144→    url: persisted.url,
145→    currentUrl: persisted.url,
146→    history: persisted.url ? [persisted.url] : [],
147→    historyIndex: persisted.url ? 0 : -1,
148→    loading: false,
149→    error: null,
150→    injected: false,
151→    injectionFailed: false,
152→    selectorActive: false,
153→    devtoolsOpen: false,
154→    consoleLogs: [],
155→  };
156→}
