160→/**
161→ * Parse and validate data against a Zod schema.
162→ * Throws ValidationError with descriptive messages on failure.
163→ */
164→export function parseBody<T extends z.ZodType>(schema: T, data: unknown): z.infer<T> {
165→  const result = schema.safeParse(data);
166→  if (!result.success) {
167→    const messages = result.error.issues.map((i) => {
168→      const path = i.path.length > 0 ? `${i.path.join('.')}: ` : '';
169→      return `${path}${i.message}`;
170→    });
171→    throw new ValidationError(messages.join('; '));
172→  }
173→  return result.data;
174→}
