 1→import { Hono } from 'hono';
 2→import Database from 'better-sqlite3';
 3→import { existsSync, readdirSync } from 'fs';
 4→import { homedir } from 'os';
 5→import { join, basename } from 'path';
 6→
 7→const app = new Hono();
 8→
 9→interface RecentProject {
10→  path: string;
11→  name: string;
12→  source: 'cursor' | 'vscode' | 'claude';
13→}
14→
15→app.get('/onboarding/recent-projects', (c) => {
16→  const home = homedir();
17→  const projects: RecentProject[] = [];
18→  const seenPaths = new Set<string>();
19→
20→  // Read from Cursor state.vscdb
21→  const cursorDbPath = join(home, 'Library/Application Support/Cursor/User/globalStorage/state.vscdb');
22→  readVscdbProjects(cursorDbPath, 'cursor', projects, seenPaths);
23→
24→  // Read from VSCode state.vscdb
25→  const vscodeDbPath = join(home, 'Library/Application Support/Code/User/globalStorage/state.vscdb');
26→  readVscdbProjects(vscodeDbPath, 'vscode', projects, seenPaths);
27→
28→  // Read from Claude projects directory
29→  readClaudeProjects(join(home, '.claude/projects'), projects, seenPaths);
30→
31→  return c.json({ projects: projects.slice(0, 30) });
32→});
33→
34→function readVscdbProjects(
35→  dbPath: string,
36→  source: 'cursor' | 'vscode',
37→  projects: RecentProject[],
38→  seen: Set<string>
39→) {
40→  if (!existsSync(dbPath)) return;
41→  try {
42→    const db = new Database(dbPath, { readonly: true });
43→    const row = db.prepare(
44→      "SELECT value FROM ItemTable WHERE key = 'history.recentlyOpenedPathsList'"
45→    ).get() as { value: string } | undefined;
46→    db.close();
47→
48→    if (!row?.value) return;
49→    const data = JSON.parse(row.value);
50→    const entries = data.entries || [];
51→
52→    for (const entry of entries) {
53→      const uri = entry.folderUri;
54→      if (!uri || !uri.startsWith('file://')) continue;
55→      const fsPath = decodeURIComponent(uri.replace('file://', ''));
56→      if (seen.has(fsPath) || !existsSync(fsPath)) continue;
57→      seen.add(fsPath);
58→      projects.push({ path: fsPath, name: basename(fsPath), source });
59→    }
60→  } catch {
61→    // Silently skip if DB is locked or malformed
62→  }
63→}
64→
65→function readClaudeProjects(dir: string, projects: RecentProject[], seen: Set<string>) {
66→  if (!existsSync(dir)) return;
67→  try {
68→    const entries = readdirSync(dir, { withFileTypes: true });
69→    for (const entry of entries) {
70→      if (!entry.isDirectory()) continue;
71→      // Claude encodes paths: leading dash + dashes as path separators
72→      // e.g., "-Users-zvada-Developer-myproject" -> "/Users/zvada/Developer/myproject"
73→      const decoded = entry.name.replace(/-/g, '/');
74→      if (!decoded.startsWith('/')) continue;
75→      if (seen.has(decoded) || !existsSync(decoded)) continue;
76→      seen.add(decoded);
77→      projects.push({ path: decoded, name: basename(decoded), source: 'claude' });
78→    }
79→  } catch {
80→    // Silently skip
81→  }
82→}
83→
84→export default app;
