  2→import path from 'path';
  3→import fs from 'fs';
  4→import { execFileSync } from 'child_process';
  5→import { uuidv7 } from '@shared/lib/uuid';
  6→import { getDatabase } from '../lib/database';
  7→import { AppError, ValidationError, ConflictError, NotFoundError } from '../lib/errors';
  8→import { parseBody, CreateRepoBody } from '../lib/schemas';
  9→import { detectDefaultBranch } from '../services/git.service';
 10→import { getAllRepositories, getRepositoryByRootPath, getRepositoryById, getMaxRepositorySortOrder } from '../db';
 11→import { readManifest, getNormalizedTasks, writeManifest, detectManifestFromProject } from '../services/manifest.service';
 12→import { OpenDevsManifestSchema } from '../lib/opendevs-manifest';
 13→import { invalidate } from '../services/query-engine';
 14→import type { QueryResource } from '../../../shared/types/query-protocol';
 15→
 16→const app = new Hono();
 17→
 18→app.get('/repos', (c) => {
 19→  const db = getDatabase();
 20→  return c.json(getAllRepositories(db));
 21→});
 22→
 23→app.post('/repos', async (c) => {
 24→  const db = getDatabase();
 25→  let { root_path } = parseBody(CreateRepoBody, await c.req.json());
 26→
 27→  // Normalize path
 28→  try { root_path = fs.realpathSync(root_path); }
 29→  catch { throw new ValidationError('Path does not exist or is inaccessible'); }
 30→
 31→  // Verify permissions
 32→  try { fs.accessSync(root_path, fs.constants.R_OK | fs.constants.X_OK); }
 33→  catch { throw new AppError(403, 'Path is not accessible (permission denied)'); }
 34→
 35→  const stats = fs.statSync(root_path);
 36→  if (!stats.isDirectory()) throw new ValidationError('Path is not a directory');
 37→
 38→  // Check git repo
 39→  try { execFileSync('git', ['rev-parse', '--is-inside-work-tree'], { cwd: root_path, timeout: 2000 }); }
 40→  catch { throw new ValidationError('Path is not a git repository'); }
 41→
 42→  const repoName = path.basename(root_path);
 43→  const defaultBranch = detectDefaultBranch(root_path);
 44→
 45→  const insertRepo = db.transaction((root_path: string, repoId: string, repoName: string, defaultBranch: string) => {
 46→    const existing = getRepositoryByRootPath(db, root_path);
 47→    if (existing) throw new ConflictError('Repository already exists', existing);
 48→
 49→    const sortOrder = getMaxRepositorySortOrder(db) + 1;
 50→
 51→    db.prepare(`
 52→      INSERT INTO repositories (id, name, root_path, git_default_branch, sort_order)
 53→      VALUES (?, ?, ?, ?, ?)
 54→    `).run(repoId, repoName, root_path, defaultBranch, sortOrder);
 55→
 56→    return getRepositoryById(db, repoId);
 57→  });
 58→
 59→  const repoId = uuidv7();
 60→  const repo = insertRepo(root_path, repoId, repoName, defaultBranch);
 61→  invalidate(["stats"] as QueryResource[]);
 62→  return c.json(repo, 201);
 63→});
 64→
 65→// ─── Manifest Endpoints (per-repo, settings UI) ─────────────
 66→
 67→// Read manifest from repo root
 68→app.get('/repos/:id/manifest', (c) => {
 69→  const db = getDatabase();
 70→  const repo = getRepositoryById(db, c.req.param('id'));
 71→  if (!repo) throw new NotFoundError('Repository not found');
 72→
 73→  const manifest = readManifest(repo.root_path);
 74→  if (!manifest) return c.json({ manifest: null, tasks: [] });
 75→  const tasks = getNormalizedTasks(manifest);
 76→  return c.json({ manifest, tasks });
 77→});
 78→
 79→// Write manifest to repo root
 80→app.post('/repos/:id/manifest', async (c) => {
 81→  const db = getDatabase();
 82→  const repo = getRepositoryById(db, c.req.param('id'));
 83→  if (!repo) throw new NotFoundError('Repository not found');
 84→
 85→  const manifest = parseBody(OpenDevsManifestSchema, await c.req.json());
 86→  const success = writeManifest(repo.root_path, manifest);
 87→  if (!success) return c.json({ error: 'Failed to write manifest' }, 500);
 88→  return c.json({ success: true });
 89→});
 90→
 91→// Auto-detect manifest from project files (package.json, Cargo.toml, etc.)
 92→app.get('/repos/:id/detect-manifest', (c) => {
 93→  const db = getDatabase();
 94→  const repo = getRepositoryById(db, c.req.param('id'));
 95→  if (!repo) throw new NotFoundError('Repository not found');
 96→
 97→  const manifest = detectManifestFromProject(repo.root_path, repo.name);
 98→  return c.json({ manifest });
 99→});
