177→// ─── Message Queries ─────────────────────────────────────────
178→
179→/**
180→ * Fetch paginated messages for a session.
181→ * Uses seq (per-session monotonic integer) as cursor — no collisions,
182→ * no NULLs, integer comparison. sent_at had 15K+ collisions in production.
183→ */
184→export function getMessages(
185→  db: Database.Database,
186→  sessionId: string,
187→  opts: { limit: number; before?: number; after?: number }
188→): MessageRow[] {
189→  if (opts.before) {
190→    // Load older: fetch N messages before seq, then re-sort ascending
191→    return db.prepare(`
192→      SELECT * FROM (
193→        SELECT * FROM messages
194→        WHERE session_id = ? AND seq < ?
195→        ORDER BY seq DESC
196→        LIMIT ?
197→      ) sub ORDER BY seq ASC
198→    `).all(sessionId, opts.before, opts.limit) as MessageRow[];
199→  }
200→
201→  if (opts.after) {
202→    // Load newer: fetch N messages after seq, already in ascending order
203→    return db.prepare(`
204→      SELECT * FROM messages
205→      WHERE session_id = ? AND seq > ?
206→      ORDER BY seq ASC
207→      LIMIT ?
208→    `).all(sessionId, opts.after, opts.limit) as MessageRow[];
209→  }
210→
211→  // Default: load latest N messages (DESC then re-wrap ASC)
212→  return db.prepare(`
213→    SELECT * FROM (
214→      SELECT * FROM messages
215→      WHERE session_id = ?
216→      ORDER BY seq DESC
217→      LIMIT ?
218→    ) sub ORDER BY seq ASC
219→  `).all(sessionId, opts.limit) as MessageRow[];
220→}
