108→/**
109→ * Scan a project directory and generate a suggested opendevs.json manifest.
110→ * Reads package.json, Cargo.toml, Makefile, etc. to infer scripts and tasks.
111→ */
112→export function detectManifestFromProject(rootPath: string, repoName: string): Record<string, unknown> {
113→  const manifest: Record<string, unknown> = { version: 1, name: repoName };
114→  const tasks: Record<string, unknown> = {};
115→  const requires: Record<string, string> = {};
116→
117→  // Detect Node.js / Bun project
118→  const pkgJsonPath = path.join(rootPath, 'package.json');
119→  if (fs.existsSync(pkgJsonPath)) {
120→    try {
121→      const pkg = JSON.parse(fs.readFileSync(pkgJsonPath, 'utf-8'));
122→      const pm = (fs.existsSync(path.join(rootPath, 'bun.lock')) || fs.existsSync(path.join(rootPath, 'bun.lockb'))) ? 'bun' :
123→                 fs.existsSync(path.join(rootPath, 'pnpm-lock.yaml')) ? 'pnpm' :
124→                 fs.existsSync(path.join(rootPath, 'yarn.lock')) ? 'yarn' : 'npm';
125→      const run = pm === 'npm' ? 'npm run' : `${pm} run`;
126→
127→      requires[pm] = '>= 1.0';
128→      if (pm !== 'bun') requires.node = '>= 18';
129→
130→      manifest.scripts = { setup: `${pm} install` };
131→      manifest.lifecycle = { setup: `${pm} install` };
132→
133→      const scripts = pkg.scripts || {};
134→      if (scripts.dev) tasks.dev = { command: `${run} dev`, description: 'Start dev server', icon: 'play', persistent: true };
135→      if (scripts.build) tasks.build = { command: `${run} build`, description: 'Build for production', icon: 'hammer' };
136→      if (scripts.test) tasks.test = { command: `${run} test`, description: 'Run tests', icon: 'check-circle' };
137→      if (scripts.lint) tasks.lint = { command: `${run} lint`, description: 'Lint code', icon: 'search-code' };
138→      if (scripts.format) tasks.format = { command: `${run} format`, description: 'Format code', icon: 'paintbrush' };
139→      if (scripts.typecheck) tasks.typecheck = { command: `${run} typecheck`, description: 'Type check', icon: 'search-code' };
140→      if (scripts.start) tasks.start = { command: `${run} start`, description: 'Start production server', icon: 'rocket', persistent: true };
141→    } catch { /* invalid package.json — skip */ }
142→  }
143→
144→  // Detect Rust project
145→  const cargoPath = path.join(rootPath, 'Cargo.toml');
146→  if (fs.existsSync(cargoPath)) {
147→    requires.cargo = '>= 1.0';
148→    if (!manifest.scripts) manifest.scripts = { setup: 'cargo build' };
149→    if (!manifest.lifecycle) manifest.lifecycle = { setup: 'cargo build' };
150→    if (!tasks.build) tasks.build = { command: 'cargo build --release', description: 'Build release', icon: 'hammer' };

