 3→/**
 4→ * Zod schemas for opendevs.json manifest.
 5→ *
 6→ * TaskEntry supports string shorthand ("bun run test") or full object form.
 7→ * OpenDevsManifest is the top-level schema — parsed with safeParse for graceful fallback.
 8→ */
 9→
10→const TaskObjectSchema = z.object({
11→  command: z.string().min(1),
12→  description: z.string().optional(),
13→  icon: z.string().optional(),
14→  persistent: z.boolean().optional(),
15→  mode: z.enum(['concurrent', 'nonconcurrent']).optional(),
16→  depends: z.array(z.string()).optional(),
17→  platform: z.array(z.string()).optional(),
18→  env: z.record(z.string(), z.string()).optional(),
19→}).passthrough();
20→
21→const TaskEntrySchema = z.union([z.string().min(1), TaskObjectSchema]);
22→
23→export const OpenDevsManifestSchema = z.object({
24→  $schema: z.string().optional(),
25→  version: z.number(),
26→  name: z.string().optional(),
27→  scripts: z.object({
28→    setup: z.string().optional(),
29→    run: z.string().optional(),
30→    archive: z.string().optional(),
31→  }).passthrough().optional(),
32→  runScriptMode: z.enum(['concurrent', 'nonconcurrent']).optional(),
33→  requires: z.record(z.string(), z.string()).optional(),
34→  env: z.record(z.string(), z.string()).optional(),
35→  lifecycle: z.object({
36→    setup: z.string().optional(),
37→    archive: z.string().optional(),
38→  }).passthrough().optional(),
39→  tasks: z.record(z.string(), TaskEntrySchema).optional(),
40→}).passthrough();
41→
42→export type OpenDevsManifest = z.infer<typeof OpenDevsManifestSchema>;
