 25→  }
 26→
 27→  /**
 28→   * Generic POST request
 29→   */
 30→  async post<T>(endpoint: string, data?: any): Promise<T> {
 31→    return this.request<T>(endpoint, {
 32→      method: "POST",
 33→      headers: { "Content-Type": "application/json" },
 34→      body: data ? JSON.stringify(data) : undefined,
 35→    });
 36→  }
 37→
 38→  /**
 39→   * Generic PUT request
 40→   */
 41→  async put<T>(endpoint: string, data?: any): Promise<T> {
 42→    return this.request<T>(endpoint, {
 43→      method: "PUT",
 44→      headers: { "Content-Type": "application/json" },
 45→      body: data ? JSON.stringify(data) : undefined,
 46→    });
 47→  }
 48→
 49→  /**
 50→   * Generic PATCH request
 51→   */
 52→  async patch<T>(endpoint: string, data: any): Promise<T> {
 53→    return this.request<T>(endpoint, {
 54→      method: "PATCH",
 55→      headers: { "Content-Type": "application/json" },
 56→      body: JSON.stringify(data),
 57→    });
 58→  }
 59→
 60→  /**
 61→   * Generic DELETE request
 62→   */
 63→  async delete<T>(endpoint: string): Promise<T> {
 64→    return this.request<T>(endpoint, { method: "DELETE" });
 65→  }
 66→
 67→  /**
 68→   * Core request method with timeout and error handling.
 69→   * Attaches Authorization header for remote browser clients.
 70→   */
 71→  private async request<T>(endpoint: string, options: RequestInit): Promise<T> {
 72→    const baseURL = await getBaseURL();
 73→    const url = `${baseURL}${endpoint}`;
 74→    const controller = new AbortController();
 75→    const timeoutId = setTimeout(() => controller.abort(), this.timeout);
 76→
 77→    // Attach Bearer token for remote (non-localhost) browser sessions
 78→    const headers = new Headers(options.headers);
 79→    if (needsRemoteAuth()) {
 80→      const token = getStoredToken();
 81→      if (token) {
 82→        headers.set("Authorization", `Bearer ${token}`);
 83→      }
 84→    }
 85→
 86→    try {
 87→      const response = await fetch(url, {
 88→        ...options,
 89→        headers,
 90→        signal: controller.signal,
 91→      });
 92→
 93→      clearTimeout(timeoutId);
 94→
 95→      if (!response.ok) {
 96→        const error: ApiError = {
 97→          status: response.status,
 98→          message: response.statusText,
 99→        };
100→
101→        try {
102→          const errorData = await response.json();
103→          error.details = errorData;
104→          error.message = errorData.error || errorData.message || error.message;
105→        } catch {
106→          // Response is not JSON
107→        }
108→
109→        throw error;
110→      }
111→
112→      // Handle empty responses
113→      const contentType = response.headers.get("content-type");
114→      if (!contentType || !contentType.includes("application/json")) {
115→        return null as T;
116→      }
117→
118→      return await response.json();
119→    } catch (error) {
120→      clearTimeout(timeoutId);
121→
122→      if (error instanceof Error) {
123→        if (error.name === "AbortError") {
124→          throw {
125→            status: 408,
126→            message: "Request timeout",
127→            details: error,
128→          } as ApiError;
129→        }
130→        throw {
131→          status: 0,
132→          message: error.message,
133→          details: error,
134→        } as ApiError;
135→      }
136→
137→      throw error;
138→    }
139→  }
140→}
