  1→// backend/src/services/remote-auth.service.ts
  2→// Core auth logic for remote access: pairing codes, device tokens, rate limiting.
  3→// Pairing codes are ephemeral (in-memory), device tokens are persistent (DB).
  4→
  5→import { randomBytes, randomInt, createHash } from "crypto";
  6→import { getDatabase } from "../lib/database";
  7→import { getSetting, saveSetting } from "./settings.service";
  8→
  9→// ---- Types ----
 10→
 11→export interface PairedDevice {
 12→  id: string;
 13→  name: string;
 14→  token_hash: string;
 15→  ip_address: string | null;
 16→  user_agent: string | null;
 17→  last_seen_at: string;
 18→  created_at: string;
 19→}
 20→
 21→interface PairingCode {
 22→  code: string;
 23→  createdAt: number;
 24→  expiresAt: number;
 25→}
 26→
 27→interface RateLimitEntry {
 28→  failures: number;
 29→  lockedUntil: number;
 30→}
 31→
 32→// ---- Constants ----
 33→
 34→const MAX_ACTIVE_CODES = 5;
 35→const CODE_TTL_MS = 15 * 60 * 1000; // 15 minutes
 36→const RATE_LIMIT_FAILURES = 10;
 37→const RATE_LIMIT_LOCKOUT_MS = 5 * 60 * 1000; // 5 minutes
 38→
 39→// 100 short, memorable words for pairing codes
 40→const WORD_LIST = [
 41→  "ALPHA", "BEAR", "BOLT", "BRAVE", "BYTE",
 42→  "CEDAR", "CLOUD", "CORAL", "CRANE", "CROWN",
 43→  "DAWN", "DELTA", "DRIFT", "DUNE", "EAGLE",
 44→  "EMBER", "FERN", "FLAME", "FLASH", "FLINT",
 45→  "FORGE", "FROST", "GLOW", "GROVE", "HAWK",
 46→  "HAVEN", "HAZE", "HELM", "HIVE", "IRON",
 47→  "JADE", "KEEN", "LAKE", "LARK", "LEAF",
 48→  "LIGHT", "LIME", "LINK", "LUNA", "LYNX",
 49→  "MAPLE", "MARS", "MESA", "MINT", "MIST",
 50→  "MOSS", "NIGHT", "NODE", "NOVA", "OAK",
 51→  "OPAL", "ORBIT", "PALM", "PEAK", "PINE",
 52→  "PIXEL", "PLUM", "POLAR", "PULSE", "QUARTZ",
 53→  "RAIN", "RAPID", "REEF", "RIDGE", "RIVER",
 54→  "ROBIN", "RUNE", "RUSH", "SAGE", "SHELL",
 55→  "SILK", "SKY", "SLATE", "SOLAR", "SPARK",
 56→  "SPIRE", "STEEL", "STONE", "STORM", "SWIFT",
 57→  "THORN", "TIDE", "TIGER", "TRAIL", "TREE",
 58→  "VALE", "VAPOR", "VINE", "VIPER", "WAVE",
 59→  "WHALE", "WIND", "WING", "WOLF", "WREN",
 60→  "YACHT", "YARN", "ZENITH", "ZINC", "ZONE",
 61→];
 62→
 63→// ---- In-memory state ----
 64→
 65→const activeCodes = new Map<string, PairingCode>();
 66→const rateLimits = new Map<string, RateLimitEntry>();
 67→
 68→// ---- Pairing Codes ----
 69→
 70→/** Generate a WORD-NNNN pairing code. Returns the code string and its expiry. */
 71→export function generatePairCode(): { code: string; expiresAt: number } {
 72→  // Evict expired codes first
 73→  const now = Date.now();
 74→  for (const [key, entry] of activeCodes) {
 75→    if (entry.expiresAt <= now) activeCodes.delete(key);
 76→  }
 77→
 78→  // Enforce max active codes
 79→  if (activeCodes.size >= MAX_ACTIVE_CODES) {
 80→    // Evict oldest
 81→    let oldestKey: string | null = null;
 82→    let oldestTime = Infinity;
 83→    for (const [key, entry] of activeCodes) {
 84→      if (entry.createdAt < oldestTime) {
 85→        oldestTime = entry.createdAt;
 86→        oldestKey = key;
 87→      }
 88→    }
 89→    if (oldestKey) activeCodes.delete(oldestKey);
 90→  }
 91→
 92→  const word = WORD_LIST[randomInt(WORD_LIST.length)];
 93→  const number = String(randomInt(1000, 10000)); // 1000-9999
 94→  const code = `${word}-${number}`;
 95→  const expiresAt = now + CODE_TTL_MS;
 96→
 97→  activeCodes.set(code, { code, createdAt: now, expiresAt });
 98→  return { code, expiresAt };
 99→}
100→
101→/** Validate and consume a pairing code. Returns true if valid (one-time use). */
102→export function validatePairCode(code: string): boolean {
103→  const upper = code.toUpperCase().trim();
104→  const entry = activeCodes.get(upper);
105→  if (!entry) {
106→    console.log(`[Auth] Code "${upper}" not found. Active codes: ${activeCodes.size} (keys: ${[...activeCodes.keys()].join(", ") || "none"})`);
107→    return false;
108→  }
109→  if (entry.expiresAt <= Date.now()) {
110→    activeCodes.delete(upper);
111→    return false;
112→  }
113→  // One-time use — delete immediately
114→  activeCodes.delete(upper);
115→  return true;
116→}
117→
118→/** Get number of active (non-expired) pairing codes. */
119→export function getActiveCodeCount(): number {
120→  const now = Date.now();
121→  for (const [key, entry] of activeCodes) {
122→    if (entry.expiresAt <= now) activeCodes.delete(key);
123→  }
124→  return activeCodes.size;
125→}
126→
127→// ---- Device Tokens ----
128→
129→function hashToken(token: string): string {
130→  return createHash("sha256").update(token).digest("hex");
131→}
132→
133→function generateId(): string {
134→  return randomBytes(16).toString("hex");
135→}
136→
137→/** Create a new device token. Returns the raw token (only shown once) and device record. */
138→export function createDeviceToken(
139→  name: string,
140→  ip: string | null,
141→  userAgent: string | null,
142→): { token: string; device: PairedDevice } {
143→  const token = randomBytes(32).toString("hex");
144→  const tokenHash = hashToken(token);
145→  const id = generateId();
146→
147→  const db = getDatabase();
148→  db.prepare(`
149→    INSERT INTO paired_devices (id, name, token_hash, ip_address, user_agent)
150→    VALUES (?, ?, ?, ?, ?)
151→  `).run(id, name || "Unknown Device", tokenHash, ip, userAgent);
152→
153→  const device = db.prepare("SELECT * FROM paired_devices WHERE id = ?").get(id) as PairedDevice;
154→  return { token, device };
155→}
156→
157→/** Validate a raw Bearer token. Returns the device if valid, null otherwise. */
158→export function validateDeviceToken(token: string): PairedDevice | null {
159→  const tokenHash = hashToken(token);
160→  const db = getDatabase();
161→  return (db.prepare("SELECT * FROM paired_devices WHERE token_hash = ?").get(tokenHash) as PairedDevice) ?? null;
162→}
163→
164→/** Update last_seen_at for a device by token hash. */
165→export function updateLastSeen(tokenHash: string): void {
166→  const db = getDatabase();
167→  db.prepare("UPDATE paired_devices SET last_seen_at = datetime('now') WHERE token_hash = ?").run(tokenHash);
168→}
169→
170→/** List all paired devices (token_hash excluded from the returned objects for safety). */
171→export function listDevices(): Omit<PairedDevice, "token_hash">[] {
172→  const db = getDatabase();
173→  const rows = db.prepare(
174→    "SELECT id, name, ip_address, user_agent, last_seen_at, created_at FROM paired_devices ORDER BY created_at DESC",
175→  ).all() as Omit<PairedDevice, "token_hash">[];
176→  return rows;
177→}
178→
179→/** Revoke (delete) a paired device by id. Returns true if a row was deleted. */
180→export function revokeDevice(id: string): boolean {
181→  const db = getDatabase();
182→  const result = db.prepare("DELETE FROM paired_devices WHERE id = ?").run(id);
183→  return result.changes > 0;
184→}
185→
186→// ---- Rate Limiting (per IP) ----
187→
188→/** Check if an IP is rate-limited. Returns lockout remaining ms or 0. */
189→export function checkRateLimit(ip: string): number {
190→  const entry = rateLimits.get(ip);
191→  if (!entry) return 0;
192→  const now = Date.now();
193→  if (entry.lockedUntil > now) return entry.lockedUntil - now;
194→  return 0;
195→}
196→
197→/** Record a failed pairing attempt for an IP. */
198→export function recordFailure(ip: string): void {
199→  const entry = rateLimits.get(ip) ?? { failures: 0, lockedUntil: 0 };
200→  entry.failures += 1;
201→  if (entry.failures >= RATE_LIMIT_FAILURES) {
202→    entry.lockedUntil = Date.now() + RATE_LIMIT_LOCKOUT_MS;
203→  }
204→  rateLimits.set(ip, entry);
205→}
206→
207→/** Reset rate limit for an IP (called on successful pairing). */
208→export function resetRateLimit(ip: string): void {
209→  rateLimits.delete(ip);
210→}
211→
212→// ---- Relay Credentials ----
213→
214→/** Generate relay credentials (server_id + relay_token). Stores in preferences.json. */
215→export function generateRelayCredentials(): { serverId: string; relayToken: string } {
216→  const serverId = randomBytes(4).toString("hex"); // 8-char hex
217→  const relayToken = randomBytes(32).toString("hex");
218→  saveSetting("relay_server_id", serverId);
219→  saveSetting("relay_token", relayToken);
220→  return { serverId, relayToken };
221→}
222→
223→/** Get stored relay credentials, or null if not yet generated. */
224→export function getRelayCredentials(): { serverId: string; relayToken: string } | null {
225→  const serverId = getSetting("relay_server_id");
226→  const relayToken = getSetting("relay_token");
227→  if (!serverId || !relayToken) return null;
228→  return { serverId, relayToken };
229→}
230→
231→// ---- Test Helpers (exported for testing only) ----
232→
233→export function _clearAll(): void {
234→  activeCodes.clear();
235→  rateLimits.clear();
236→}
