 1→// backend/src/routes/remote-auth.ts
 2→// Auth endpoints for remote access pairing and device management.
 3→// POST /remote-auth/pair — public, rate-limited, exchanges code for token
 4→// POST /remote-auth/generate-pair-code — localhost-only, creates a new code
 5→// GET /remote-auth/devices — localhost-only, lists paired devices
 6→// DELETE /remote-auth/devices/:id — localhost-only, revokes a device
 7→
 8→import { Hono } from "hono";
 9→import { createMiddleware } from "hono/factory";
10→import { parseBody, PairBody } from "../lib/schemas";
11→import {
12→  generatePairCode,
13→  validatePairCode,
14→  createDeviceToken,
15→  listDevices,
16→  revokeDevice,
17→  checkRateLimit,
18→  recordFailure,
19→  resetRateLimit,
20→} from "../services/remote-auth.service";
21→import { isLocalhost, getClientIp } from "../lib/network";
22→
23→const app = new Hono();
24→
25→/** Reject non-localhost requests with 403. */
26→const localhostOnly = createMiddleware(async (c, next) => {
27→  if (!isLocalhost(getClientIp(c))) {
28→    return c.json({ error: "This endpoint is only available from localhost" }, 403);
29→  }
30→  await next();
31→});
32→
33→// POST /remote-auth/pair — public, exchanges pairing code for device token
34→app.post("/remote-auth/pair", async (c) => {
35→  const clientIp = getClientIp(c);
36→
37→  // Rate limit check
38→  if (clientIp) {
39→    const lockout = checkRateLimit(clientIp);
40→    if (lockout > 0) {
41→      return c.json({ error: "Too many failed attempts. Try again later." }, 429);
42→    }
43→  }
44→
45→  const { code, deviceName } = parseBody(PairBody, await c.req.json());
46→
47→  if (!validatePairCode(code)) {
48→    if (clientIp) recordFailure(clientIp);
49→    return c.json({ error: "Invalid or expired pairing code" }, 401);
50→  }
51→
52→  // Successful pairing — create device token
53→  if (clientIp) resetRateLimit(clientIp);
54→  const userAgent = c.req.header("user-agent") ?? null;
55→  const { token, device } = createDeviceToken(
56→    deviceName ?? "Unknown Device",
57→    clientIp ?? null,
58→    userAgent,
59→  );
60→
61→  return c.json({
62→    token,
63→    device: {
64→      id: device.id,
65→      name: device.name,
66→      created_at: device.created_at,
67→    },
68→  });
69→});
70→
71→// POST /remote-auth/generate-pair-code — localhost-only
72→app.post("/remote-auth/generate-pair-code", localhostOnly, (c) => {
73→  const { code, expiresAt } = generatePairCode();
74→  const expiresInSeconds = Math.round((expiresAt - Date.now()) / 1000);
75→
76→  return c.json({ code, expires_in_seconds: expiresInSeconds });
77→});
78→
79→// GET /remote-auth/devices — localhost-only
80→app.get("/remote-auth/devices", localhostOnly, (c) => {
81→  return c.json({ devices: listDevices() });
82→});
83→
84→// DELETE /remote-auth/devices/:id — localhost-only
85→app.delete("/remote-auth/devices/:id", localhostOnly, (c) => {
86→  const id = c.req.param("id");
87→  const deleted = revokeDevice(id);
88→  if (!deleted) {
89→    return c.json({ error: "Device not found" }, 404);
90→  }
91→  return c.json({ success: true });
92→});
93→
94→export default app;
