126→// Create workspace
127→app.post('/workspaces', async (c) => {
128→  const db = getDatabase();
129→  const { repository_id } = parseBody(CreateWorkspaceBody, await c.req.json());
130→
131→  const repo = getRepositoryById(db, repository_id);
132→  if (!repo) throw new NotFoundError('Repository not found');
133→
134→  const workspace_name = generateUniqueName(db);
135→  const parent_branch = repo.git_default_branch || 'main';
136→  const workspaceId = uuidv7();
137→
138→  let branchPrefix = 'workspace';
139→  try {
140→    const gitUser = execSync('git config user.name', { cwd: repo.root_path!, encoding: 'utf8' })
141→      .trim().toLowerCase().replace(/[^a-z0-9_-]/g, '-');
142→    if (gitUser) branchPrefix = gitUser;
143→  } catch {}
144→  const placeholderBranchName = `${branchPrefix}/${workspace_name}`;
145→
146→  // ─── IMPORTANT: Remote-first branch strategy ───────────────────────
147→  // We ALWAYS want worktrees branched from origin/<parent_branch>, not
148→  // local <parent_branch>. Diffs are computed against origin/<branch>
149→  // (see resolve_parent_branch in git.rs and git.service.ts). If origin
150→  // is stale, the merge-base drifts and every file since the divergence
151→  // shows as "changed" — producing hundreds of phantom file changes.
152→  //
153→  // Fetch the remote branch before creating the worktree so that:
154→  // 1. The worktree starts from the latest upstream commit
155→  // 2. Diff merge-base matches what we branched from (zero phantom changes)
156→  // 3. PRs will be clean against the upstream target
157→  //
158→  // This is a non-blocking fetch (~1-3s on a warm connection). Workspace
159→  // creation is already async (worktree add runs in a child process) and
160→  // correctness matters more here.
161→  // ───────────────────────────────────────────────────────────────────
162→  try {
163→    await execFileAsync('git', ['fetch', 'origin', parent_branch], {
164→      cwd: repo.root_path!,
165→      timeout: 15000,
166→    });
167→  } catch (fetchErr) {
168→    // Non-fatal: if fetch fails (offline, no remote, etc.), fall back to
169→    // whatever local state we have. The worktree will still be created
170→    // from the local branch — diffs might be off but it's better than
171→    // blocking workspace creation entirely.
172→    console.warn(`[WORKSPACE] git fetch origin ${parent_branch} failed (continuing with local):`, fetchErr);
173→  }
174→
175→  db.prepare(`
176→    INSERT INTO workspaces (
177→      id, repository_id, slug, git_branch,
178→      git_target_branch, state, updated_at
179→    ) VALUES (?, ?, ?, ?, ?, ?, datetime('now'))
180→  `).run(workspaceId, repository_id, workspace_name, placeholderBranchName,
181→    parent_branch, 'initializing');
182→
183→  // Branch from origin/<parent_branch> when available (fetched above).
184→  // Falls back to local <parent_branch> if remote doesn't exist.
185→  const worktreeBase = await (async () => {
186→    try {
187→      await execFileAsync('git', ['show-ref', '--verify', '--quiet', `refs/remotes/origin/${parent_branch}`], {
188→        cwd: repo.root_path!, timeout: 2000,
189→      });
190→      return `origin/${parent_branch}`;
191→    } catch {
192→      return parent_branch;
193→    }
194→  })();
195→
196→  const workspacePath = path.join(repo.root_path!, '.opendevs', workspace_name);
197→
198→  // Fire-and-forget: run the init pipeline async (don't await).
199→  // Pipeline handles: worktree creation → deps install → .env copy → session creation.
200→  // Progress events flow: stdout → Rust backend.rs → Tauri events → Frontend.
201→  // On fatal failure: reverse cleanup (rm dir, prune worktree, delete branch).
202→  initializeWorkspace({
203→    workspaceId,
204→    repositoryId: repository_id,
205→    repoRootPath: repo.root_path!,
206→    workspacePath,
207→    branchName: placeholderBranchName,
208→    worktreeBase,
209→    parentBranch: parent_branch,
210→  }).then(() => {
211→    // Workspace is ready — check for manifest setup script
212→    const manifest = readManifestWithFallback(workspacePath, repo.root_path!);
213→    const setupCmd = manifest ? getSetupCommand(manifest) : null;
214→    if (setupCmd && manifest) {
215→      db.prepare("UPDATE workspaces SET setup_status = 'running' WHERE id = ?").run(workspaceId);
216→      const setupEnv = getOpenDevsEnv(manifest, { id: workspaceId, rootPath: repo.root_path!, workspacePath });
217→      runSetupScript(db, workspaceId, setupCmd, setupEnv, workspacePath);
218→    }
219→  }).catch((err) => {
220→    // Belt-and-suspenders: initializeWorkspace handles its own errors,
221→    // but if something truly unexpected escapes, don't leave workspace stuck.
222→    console.error('[WORKSPACE] Unhandled init pipeline error:', err);
223→    try {
224→      db.prepare("UPDATE workspaces SET state = 'error', init_stage = 'unhandled', error_message = 'Unhandled init pipeline error' WHERE id = ? AND state = 'initializing'")
225→        .run(workspaceId);
226→      invalidate(["workspaces", "stats"]);
227→    } catch {}
228→  });
229→
230→  const workspace = getWorkspaceForMiddleware(db, workspaceId);
231→  if (!workspace) throw new NotFoundError('Workspace not found after creation');
232→
233→  // Push immediately so clients see the workspace in 'initializing' state.
234→  // Query-protocol subscribers get snapshots + q:invalidate for unmounted caches.
235→  // The init pipeline will invalidate again when it transitions to 'ready'.
236→  invalidate(['workspaces', 'stats']);
237→
238→  return c.json({ ...workspace, workspace_path: computeWorkspacePath(workspace) });
239→});

