31→// Diff file content
32→app.get('/workspaces/:id/diff-file', withWorkspace, (c) => {
33→  const file = c.req.query('file');
34→  if (!file) throw new ValidationError('file parameter is required');
35→
36→  const workspace = c.get('workspace');
37→  const workspacePath = c.get('workspacePath');
38→  const parentBranch = gitService.resolveParentBranch(workspacePath, workspace.git_target_branch, workspace.git_default_branch);
39→  const safeFilePath = gitService.resolveWorkspaceRelativePath(workspacePath, file);
40→  if (!safeFilePath) throw new ValidationError('Invalid file path');
41→
42→  try {
43→    const output = gitService.getFileDiff(workspacePath, parentBranch, safeFilePath);
44→    const diffInfo = gitService.extractDiffInfo(output);
45→    const mergeBase = gitService.getMergeBase(workspacePath, parentBranch);
46→    const safeOldPath = gitService.resolveWorkspaceRelativePath(workspacePath, diffInfo.oldPath || safeFilePath) || safeFilePath;
47→    const safeNewPath = gitService.resolveWorkspaceRelativePath(workspacePath, diffInfo.newPath || safeFilePath) || safeFilePath;
48→
49→    let oldContent: string | null = null;
50→    let newContent: string | null = null;
51→
52→    if (diffInfo.isNew) { oldContent = ''; }
53→    else { oldContent = gitService.getGitFileContent(workspacePath, mergeBase, safeOldPath); }
54→
55→    if (diffInfo.isDeleted) { newContent = ''; }
56→    else {
57→      // Read from working directory (not HEAD) since we diff merge-base against workdir
58→      try {
59→        const buf = fs.readFileSync(path.resolve(workspacePath, safeNewPath));
60→        // Detect binary files (null bytes in first 8KB)
61→        const sample = buf.subarray(0, 8192);
62→        newContent = sample.includes(0) ? null : buf.toString('utf-8');
63→      } catch {
64→        newContent = gitService.getGitFileContent(workspacePath, 'HEAD', safeNewPath);
65→      }
66→    }
67→
68→    return c.json({ file, diff: output, old_content: oldContent, new_content: newContent });
69→  } catch (gitError: unknown) {
70→    const msg = getErrorMessage(gitError);
71→    const killed = isExecError(gitError) && gitError.killed;
72→    const errorResponse: any = {
73→      error: 'diff_failed', message: 'Failed to get diff', retryable: true,
74→      details: { file, parentBranch, reason: null as string | null }
75→    };
76→    if (killed) { errorResponse.message = 'Diff operation timed out'; errorResponse.details.reason = 'timeout'; }
77→    else if (msg.includes('unknown revision')) { errorResponse.message = 'Parent branch not found'; errorResponse.details.reason = 'branch_not_found'; errorResponse.retryable = false; }
78→    else if (msg.includes('not a git repository')) { errorResponse.message = 'Not a git repository'; errorResponse.details.reason = 'not_git_repo'; errorResponse.retryable = false; }
79→    else { errorResponse.details.reason = 'git_error'; errorResponse.details.errorMessage = msg; }
80→    return c.json(errorResponse, 500);
81→  }
82→});
