  1→/**
  2→ * Workspace Service
  3→ * API methods for workspace management operations
  4→ */
  5→
  6→import { apiClient } from "@/shared/api/client";
  7→import { ENDPOINTS } from "@/shared/config/api.config";
  8→import { isTauriAvailable } from "@/platform/tauri/invoke";
  9→import {
 10→  gitDiffStats,
 11→  gitDiffFiles,
 12→  gitDiffFile,
 13→  gitUncommittedFiles,
 14→  gitLastTurnFiles,
 15→} from "@/platform/tauri/git";
 16→import { dbGetWorkspacesByRepo } from "@/platform/tauri/db";
 17→import type { Workspace, RepoGroup, DiffStats, FileChange } from "../types";
 18→import type { PRStatus, GhCliStatus } from "@/shared/types";
 19→
 20→/** Normalized task from opendevs.json manifest */
 21→export interface NormalizedTask {
 22→  name: string;
 23→  command: string;
 24→  description: string | null;
 25→  icon: string;
 26→  persistent: boolean;
 27→  mode: "concurrent" | "nonconcurrent";
 28→  depends: string[];
 29→  env: Record<string, string>;
 30→}
 31→
 32→/** Response from GET /workspaces/:id/manifest */
 33→export interface ManifestResponse {
 34→  manifest: Record<string, unknown> | null;
 35→  tasks: NormalizedTask[];
 36→}
 37→
 38→/** Response from POST /workspaces/:id/tasks/:name/run */
 39→export interface TaskRunResponse {
 40→  ptyId: string;
 41→  command: string;
 42→  cwd: string;
 43→  env: Record<string, string>;
 44→  persistent: boolean;
 45→  mode: "concurrent" | "nonconcurrent";
 46→}
 47→
 48→/** Workspace data needed for Tauri git commands (subset of Workspace) */
 49→export interface WorkspaceGitInfo {
 50→  root_path: string;
 51→  slug: string;
 52→  workspace_path?: string;
 53→  git_target_branch?: string;
 54→  git_default_branch?: string;
 55→}
 56→
 57→function getWorkspacePath(ws: WorkspaceGitInfo): string {
 58→  if (ws.workspace_path) return ws.workspace_path;
 59→  return `${ws.root_path}/.opendevs/${ws.slug}`;
 60→}
 61→
 62→export const WorkspaceService = {
 63→  /**
 64→   * Fetch workspaces grouped by repository.
 65→   * Uses Rust/rusqlite via Tauri IPC when available (~1ms),
 66→   * falls back to Node.js HTTP when in web mode (~50-200ms).
 67→   */
 68→  fetchByRepo: async (state?: string): Promise<RepoGroup[]> => {
 69→    if (isTauriAvailable()) {
 70→      try {
 71→        return await dbGetWorkspacesByRepo(state);
 72→      } catch {
 73→        // Rust DB failed — fall through to HTTP
 74→      }
 75→    }
 76→    const query = state ? `?state=${state}` : "";
 77→    return apiClient.get<RepoGroup[]>(`${ENDPOINTS.WORKSPACES_BY_REPO}${query}`);
 78→  },
 79→
 80→  /**
 81→   * Fetch diff statistics for a workspace.
 82→   * Uses Rust/libgit2 via Tauri IPC when available (5-20ms),
 83→   * falls back to Node.js HTTP when in web mode (50-200ms).
 84→   *
 85→   * Diffs are computed against origin/<parent_branch> (remote-first).
 86→   * Workspace creation fetches origin/<parent> before branching the worktree,
 87→   * so the merge-base is always a recent shared commit with upstream.
 88→   * See: src-tauri/src/git.rs::resolve_parent_branch for the resolution logic.
 89→   */
 90→  fetchDiffStats: async (id: string, workspace?: WorkspaceGitInfo): Promise<DiffStats> => {
 91→    if (isTauriAvailable() && workspace?.root_path && workspace?.slug) {
 92→      try {
 93→        return await gitDiffStats(
 94→          getWorkspacePath(workspace),
 95→          workspace.git_target_branch || "",
 96→          workspace.git_default_branch || ""
 97→        );
 98→      } catch {
 99→        // Rust git failed (e.g., worktree deleted) — fall through to HTTP
100→      }
101→    }
102→    return apiClient.get<DiffStats>(ENDPOINTS.WORKSPACE_DIFF_STATS(id));
103→  },
104→
105→  /**
106→   * Fetch file changes for a workspace.
107→   * Uses Rust/libgit2 via Tauri IPC when available,
108→   * falls back to Node.js HTTP when in web mode.
109→   *
110→   * Returns { files, truncated, totalCount } — truncated is true when
111→   * the diff contains more than 1000 files (capped to prevent UI freeze).
112→   */
113→  fetchDiffFiles: async (
114→    id: string,
115→    workspace?: WorkspaceGitInfo
116→  ): Promise<{ files: FileChange[]; truncated?: boolean; totalCount?: number }> => {
117→    if (isTauriAvailable() && workspace?.root_path && workspace?.slug) {
118→      try {
119→        const result = await gitDiffFiles(
120→          getWorkspacePath(workspace),
121→          workspace.git_target_branch || "",
122→          workspace.git_default_branch || ""
123→        );
124→        return {
125→          files: result.files,
126→          truncated: result.truncated,
127→          totalCount: result.total_count,
128→        };
129→      } catch {
130→        // Rust git failed — fall through to HTTP
131→      }
132→    }
133→    const result = await apiClient.get<{ files: FileChange[]; truncated?: boolean; total_count?: number }>(
134→      ENDPOINTS.WORKSPACE_DIFF_FILES(id)
135→    );
136→    return {
137→      files: result.files,
138→      truncated: result.truncated ?? false,
139→      totalCount: result.total_count ?? result.files.length,
140→    };
141→  },
142→
143→  /**
144→   * Fetch diff for a specific file.
145→   * Uses Rust/libgit2 via Tauri IPC when available,
146→   * falls back to Node.js HTTP when in web mode.
147→   */
148→  fetchFileDiff: async (
149→    id: string,
150→    file: string,
151→    workspace?: WorkspaceGitInfo
152→  ): Promise<{ diff: string; oldContent: string | null; newContent: string | null }> => {
153→    if (isTauriAvailable() && workspace?.root_path && workspace?.slug) {
154→      try {
155→        const data = await gitDiffFile(
156→          getWorkspacePath(workspace),
157→          workspace.git_target_branch || "",
158→          workspace.git_default_branch || "",
159→          file
160→        );
161→        return {
162→          diff: data.diff ?? "",
163→          oldContent: data.old_content ?? null,
164→          newContent: data.new_content ?? null,
165→        };
166→      } catch {
167→        // Rust git failed — fall through to HTTP
168→      }
169→    }
170→    const data = await apiClient.get<{
171→      diff: string;
172→      old_content?: string | null;
173→      new_content?: string | null;
174→    }>(ENDPOINTS.WORKSPACE_DIFF_FILE(id, file));
175→    return {
176→      diff: data.diff ?? "",
177→      oldContent: data.old_content ?? null,
178→      newContent: data.new_content ?? null,
179→    };
180→  },
181→
182→  /**
183→   * Fetch uncommitted files (HEAD → workdir diff).
184→   * Tauri IPC only — no HTTP fallback needed.
185→   */
186→  fetchUncommittedFiles: async (workspace?: WorkspaceGitInfo): Promise<FileChange[]> => {
187→    if (!isTauriAvailable() || !workspace?.root_path || !workspace?.slug) {
188→      return [];
189→    }
190→    try {
191→      const files = await gitUncommittedFiles(getWorkspacePath(workspace));
192→      return files;
193→    } catch {
194→      return [];
195→    }
196→  },
197→
198→  /**
199→   * Fetch last-turn files (checkpoint → workdir diff).
200→   * Tauri IPC only — no HTTP fallback needed.
201→   */
202→  fetchLastTurnFiles: async (
203→    workspace?: WorkspaceGitInfo,
204→    sessionId?: string
205→  ): Promise<FileChange[]> => {
206→    if (!isTauriAvailable() || !workspace?.root_path || !workspace?.slug || !sessionId) {
207→      return [];
208→    }
209→    try {
210→      const files = await gitLastTurnFiles(getWorkspacePath(workspace), sessionId);
211→      return files;
212→    } catch {
213→      // No checkpoints exist yet — expected for new sessions
214→      return [];
215→    }
216→  },
217→
218→  /**
219→   * Create a new workspace
220→   */
221→  create: async (repositoryId: string): Promise<Workspace> => {
222→    return apiClient.post<Workspace>(ENDPOINTS.WORKSPACES, { repository_id: repositoryId });
223→  },
224→
225→  /**
226→   * Update workspace (e.g., archive)
227→   */
228→  update: async (id: string, data: Partial<Workspace>): Promise<Workspace> => {
229→    return apiClient.patch<Workspace>(ENDPOINTS.WORKSPACE_BY_ID(id), data);
230→  },
231→
232→  /**
233→   * Archive a workspace
234→   */
235→  archive: async (id: string): Promise<Workspace> => {
236→    return apiClient.patch<Workspace>(ENDPOINTS.WORKSPACE_BY_ID(id), { state: "archived" });
237→  },
238→
239→  /**
240→   * Fetch PR status for a workspace
241→   */
242→  fetchPRStatus: async (id: string): Promise<PRStatus | null> => {
243→    return apiClient.get<PRStatus | null>(ENDPOINTS.WORKSPACE_PR_STATUS(id));
244→  },
245→
246→  /**
247→   * Check GitHub CLI installation and auth status.
248→   * Cached with long staleTime on the frontend — rarely changes.
249→   */
250→  fetchGhStatus: async (): Promise<GhCliStatus> => {
251→    return apiClient.get<GhCliStatus>(ENDPOINTS.GH_STATUS);
252→  },
253→
254→  /**
255→   * Fetch system prompt for a workspace
256→   */
257→  fetchSystemPrompt: async (id: string): Promise<{ system_prompt: string }> => {
258→    return apiClient.get<{ system_prompt: string }>(ENDPOINTS.WORKSPACE_SYSTEM_PROMPT(id));
259→  },
260→
261→  /**
262→   * Fetch .pen design files in a workspace
263→   */
264→  fetchPenFiles: async (
265→    id: string
266→  ): Promise<{ files: Array<{ name: string; path: string }>; count: number }> => {
267→    return apiClient.get(ENDPOINTS.WORKSPACE_PEN_FILES(id));
268→  },
269→
270→  /**
271→   * Open a .pen file in the Pencil desktop app
272→   */
273→  openPenFile: async (id: string, filePath: string): Promise<{ success: boolean }> => {
274→    return apiClient.post(ENDPOINTS.WORKSPACE_OPEN_PEN_FILE(id), { filePath });
275→  },
276→
277→  /**
278→   * Update system prompt for a workspace
279→   */
280→  updateSystemPrompt: async (id: string, systemPrompt: string): Promise<void> => {
281→    return apiClient.put<void>(ENDPOINTS.WORKSPACE_SYSTEM_PROMPT(id), {
282→      system_prompt: systemPrompt,
283→    });
284→  },
285→
286→  /**
287→   * Fetch parsed opendevs.json manifest + normalized tasks for a workspace
288→   */
289→  fetchManifest: async (id: string): Promise<ManifestResponse> => {
290→    return apiClient.get<ManifestResponse>(ENDPOINTS.WORKSPACE_MANIFEST(id));
291→  },
292→
293→  /**
294→   * Retry a failed setup script
295→   */
296→  retrySetup: async (id: string): Promise<{ setup_status: string }> => {
297→    return apiClient.post<{ setup_status: string }>(ENDPOINTS.WORKSPACE_RETRY_SETUP(id), {});
298→  },
299→
300→  /**
301→   * Get setup log output
302→   */
303→  fetchSetupLogs: async (id: string): Promise<{ logs: string | null }> => {
304→    return apiClient.get<{ logs: string | null }>(ENDPOINTS.WORKSPACE_SETUP_LOGS(id));
305→  },
306→
307→  /**
308→   * Run a task — returns PTY spawn info
309→   */
310→  runTask: async (id: string, taskName: string): Promise<TaskRunResponse> => {
311→    return apiClient.post<TaskRunResponse>(ENDPOINTS.WORKSPACE_TASK_RUN(id, taskName), {});
312→  },
313→};
