 48→    if (!grouped[repoId]) {
 49→      grouped[repoId] = {
 50→        repo_id: repoId,
 51→        repo_name: workspace.repo_name || 'Unknown',
 52→        sort_order: workspace.repo_sort_order || 999,
 53→        workspaces: []
 54→      };
 55→    }
 56→    grouped[repoId].workspaces.push({ ...workspace, workspace_path: computeWorkspacePath(workspace) });
 57→  });
 58→
 59→  // Backfill repos that have no matching workspaces (e.g. all archived)
 60→  // so they still appear in the sidebar.
 61→  const allRepos = getAllRepositorySummaries(db);
 62→  for (const repo of allRepos) {
 63→    if (!grouped[repo.id]) {
 64→      grouped[repo.id] = {
 65→        repo_id: repo.id,
 66→        repo_name: repo.name,
 67→        sort_order: repo.sort_order ?? 999,
 68→        workspaces: [],
 69→      };
 70→    }
 71→  }
 72→
 73→  const result = Object.values(grouped).sort((a: any, b: any) => a.sort_order - b.sort_order);
 74→  return c.json(result);
 75→});
