 84→app.patch('/workspaces/:id', async (c) => {
 85→  const db = getDatabase();
 86→  const { state } = parseBody(PatchWorkspaceBody, await c.req.json());
 87→  if (state) {
 88→    db.prepare('UPDATE workspaces SET state = ? WHERE id = ?').run(state, c.req.param('id'));
 89→
 90→    // Run archive lifecycle hook (best-effort)
 91→    if (state === 'archived') {
 92→      try {
 93→        const ws = getWorkspaceById(db, c.req.param('id'));
 94→        if (ws && ws.root_path) {
 95→          const wsPath = computeWorkspacePath(ws);
 96→          const manifest = readManifestWithFallback(wsPath, ws.root_path);
 97→          const archiveCmd = manifest ? getArchiveCommand(manifest) : null;
 98→          if (archiveCmd) {
 99→            const archiveEnv = getOpenDevsEnv(manifest!, {
100→              id: ws.id,
101→              rootPath: ws.root_path,
102→              workspacePath: wsPath,
103→            });
104→            const archiveProc = spawn('sh', ['-c', archiveCmd], {
105→              cwd: wsPath,
106→              env: { ...process.env, ...archiveEnv },
107→              stdio: 'ignore',
108→              detached: false,
109→            });
110→            archiveProc.on('error', (err) => {
111→              console.error(`Archive hook error for workspace ${c.req.param('id')}:`, err.message);
112→            });
113→            archiveProc.unref();
114→          }
115→        }
116→      } catch (err) {
117→        console.warn('[WORKSPACE] Archive lifecycle hook failed (continuing):', err);
118→      }
119→    }
120→  }
121→  const updated = getWorkspaceRaw(db, c.req.param('id'));
122→  invalidate(['workspaces', 'sessions', 'stats']);
123→  return c.json(updated);
124→});
