293→// Retry failed setup
294→app.post('/workspaces/:id/retry-setup', withWorkspace, (c) => {
295→  const db = getDatabase();
296→  const workspace = c.get('workspace');
297→  const workspacePath = c.get('workspacePath');
298→
299→  if (workspace.setup_status !== 'failed') {
300→    throw new ValidationError('Can only retry when setup_status is failed');
301→  }
302→
303→  if (!workspace.root_path) {
304→    throw new ValidationError('Repository path not found');
305→  }
306→
307→  // Re-read manifest (AI agent may have fixed it, or it was added to repo root via settings)
308→  const manifest = readManifestWithFallback(workspacePath, workspace.root_path);
309→  const setupCmd = manifest ? getSetupCommand(manifest) : null;
310→  if (!setupCmd || !manifest) {
311→    db.prepare("UPDATE workspaces SET setup_status = 'none', error_message = NULL, updated_at = datetime('now') WHERE id = ?")
312→      .run(workspace.id);
313→    return c.json({ setup_status: 'none' });
314→  }
315→
316→  db.prepare("UPDATE workspaces SET setup_status = 'running', error_message = NULL, updated_at = datetime('now') WHERE id = ?")
317→    .run(workspace.id);
318→
319→  const setupEnv = getOpenDevsEnv(manifest, {
320→    id: workspace.id,
321→    rootPath: workspace.root_path,
322→    workspacePath,
323→  });
324→  runSetupScript(db, workspace.id, setupCmd, setupEnv, workspacePath);
325→
326→  return c.json({ setup_status: 'running' });
327→});
