  1→import { Hono } from 'hono';
  2→import { getDatabase } from '../lib/database';
  3→import { NotFoundError } from '../lib/errors';
  4→import { parseBody, CreateMessageBody } from '../lib/schemas';
  5→import {
  6→  getAllSessions,
  7→  getSessionById,
  8→  getSessionRaw,
  9→  getMessages,
 10→  hasOlderMessages,
 11→  hasNewerMessages,
 12→  getMessageById,
 13→} from '../db';
 14→import { invalidate } from '../services/query-engine';
 15→import { writeUserMessage } from '../services/message-writer';
 16→
 17→/**
 18→ * Session Routes
 19→ *
 20→ * Sessions are associated with workspaces. Agent runtime (Claude SDK)
 21→ * is managed by sidecar-v2 (Rust-spawned). This route handles:
 22→ * - Session CRUD
 23→ * - User message persistence
 24→ * - Session status updates
 25→ *
 26→ * Frontend communicates with sidecar-v2 via Tauri IPC for agent queries.
 27→ */
 28→
 29→const app = new Hono();
 30→
 31→app.get('/sessions', (c) => {
 32→  const db = getDatabase();
 33→  return c.json(getAllSessions(db));
 34→});
 35→
 36→app.get('/sessions/:id', (c) => {
 37→  const db = getDatabase();
 38→  const session = getSessionById(db, c.req.param('id'));
 39→  if (!session) throw new NotFoundError('Session not found');
 40→  return c.json(session);
 41→});
 42→
 43→app.get('/sessions/:id/messages', (c) => {
 44→  const db = getDatabase();
 45→  const sessionId = c.req.param('id');
 46→  // Default to 50 messages per page; cap at 500 for safety.
 47→  const limit = Math.min(Number(c.req.query('limit')) || 50, 500);
 48→  // Cursor is seq (integer), not sent_at (string with collisions)
 49→  const beforeRaw = c.req.query('before');
 50→  const afterRaw = c.req.query('after');
 51→  const before = beforeRaw ? Number(beforeRaw) : undefined;
 52→  const after = afterRaw ? Number(afterRaw) : undefined;
 53→
 54→  const messages = getMessages(db, sessionId, { limit, before, after });
 55→
 56→  // Check if there are older/newer messages using seq boundaries
 57→  const oldestSeq = messages.length > 0 ? messages[0].seq : null;
 58→  const newestSeq = messages.length > 0 ? messages[messages.length - 1].seq : null;
 59→
 60→  const has_older = oldestSeq != null ? hasOlderMessages(db, sessionId, oldestSeq) : false;
 61→  const has_newer = newestSeq != null ? hasNewerMessages(db, sessionId, newestSeq) : false;
 62→
 63→  return c.json({ messages, has_older, has_newer });
 64→});
 65→
 66→/**
 67→ * POST /sessions/:id/messages
 68→ *
 69→ * Gateway/web fallback for saving user messages. The primary desktop path
 70→ * now uses the sidecar socket (saveUserMessage in sidecar/db/session-writer.ts)
 71→ * which atomically persists the message + dispatches the agent in one call.
 72→ * This endpoint is kept for non-Tauri clients (cloud relay, web gateway).
 73→ */
 74→app.post('/sessions/:id/messages', async (c) => {
 75→  const sessionId = c.req.param('id');
 76→  const { content, model } = parseBody(CreateMessageBody, await c.req.json());
 77→
 78→  const result = writeUserMessage(sessionId, content, model);
 79→  if (!result.success) throw new NotFoundError(result.error);
 80→
 81→  invalidate(['workspaces', 'sessions', 'messages', 'stats']);
 82→
 83→  const db = getDatabase();
 84→  const createdMessage = getMessageById(db, result.messageId);
 85→  return c.json(createdMessage);
 86→});
 87→
 88→/**
 89→ * POST /sessions/:id/stop
 90→ *
 91→ * Marks session as idle and cancels latest user message.
 92→ * Actual agent cancellation is done via Tauri IPC → sidecar-v2.
 93→ */
 94→app.post('/sessions/:id/stop', (c) => {
 95→  const db = getDatabase();
 96→  const sessionId = c.req.param('id');
 97→
 98→  const session = getSessionRaw(db, sessionId);
 99→  if (!session) throw new NotFoundError('Session not found');
100→
101→  db.prepare("UPDATE sessions SET status = 'idle', updated_at = datetime('now') WHERE id = ?").run(sessionId);
102→  invalidate(['workspaces', 'sessions', 'stats']);
103→
104→  const updatedSession = getSessionRaw(db, sessionId);
105→  return c.json({ success: true, session: updatedSession });
106→});
107→
108→export default app;
