  9→import { detectDefaultBranch } from '../services/git.service';
 10→import { getAllRepositories, getRepositoryByRootPath, getRepositoryById, getMaxRepositorySortOrder } from '../db';
 11→import { readManifest, getNormalizedTasks, writeManifest, detectManifestFromProject } from '../services/manifest.service';
