  1→/**
  2→ * Tauri Platform Wrapper
  3→ *
  4→ * Provides a platform-independent interface for Tauri-specific APIs.
  5→ * This abstraction allows for easier testing and potential platform swaps.
  6→ */
  7→
  8→import { invoke as tauriInvoke } from "@tauri-apps/api/core";
  9→import { emit as tauriEmit, listen as tauriListen, type UnlistenFn } from "@tauri-apps/api/event";
 10→import { normalizeError, reportError } from "@/shared/utils/errorReporting";
 11→import { AppEventSchemaMap, type AppEventMap, type AppEventName } from "@shared/events";
 12→
 13→// Check if running in Tauri environment
 14→export const isTauriEnv =
 15→  typeof window !== "undefined" &&
 16→  ("__TAURI__" in window || "__TAURI_INTERNALS__" in window || "__TAURI_IPC__" in window);
 17→
 18→/**
 19→ * Invoke a Tauri command
 20→ * Falls back to mock implementation in non-Tauri environments
 21→ */
 22→export async function invoke<T = unknown>(
 23→  command: string,
 24→  args?: Record<string, unknown>
 25→): Promise<T> {
 26→  if (!isTauriEnv) {
 27→    console.warn(`[Platform] Tauri invoke called in non-Tauri environment: ${command}`);
 28→    throw new Error(`Tauri command not available in web mode: ${command}`);
 29→  }
 30→
 31→  try {
 32→    return await tauriInvoke<T>(command, args);
 33→  } catch (error) {
 34→    const normalized = normalizeError(error);
 35→    reportError(normalized, {
 36→      source: "tauri.invoke",
 37→      action: command,
 38→      extra: { argsKeys: args ? Object.keys(args) : undefined },
 39→    });
 40→    throw normalized;
 41→  }
 42→}
 43→
 44→/**
 45→ * Type-safe event listener.
 46→ *
 47→ * When called with a known event name from AppEventMap, the payload type
 48→ * is inferred automatically — no manual generic needed:
 49→ *
 50→ *   listen(SESSION_MESSAGE, (e) => e.payload.id)  // payload is SessionMessageEvent
 51→ *
 52→ * Also accepts arbitrary event names with an explicit generic for backwards
 53→ * compat during incremental migration:
 54→ *
 55→ *   listen<MyType>("custom:event", handler)
 56→ */
 57→export async function listen<K extends AppEventName>(
 58→  event: K,
 59→  handler: (event: { payload: AppEventMap[K] }) => void,
 60→): Promise<UnlistenFn>;
 61→export async function listen<T>(
 62→  event: string,
 63→  handler: (event: { payload: T }) => void,
 64→): Promise<UnlistenFn>;
 65→export async function listen(
 66→  event: string,
 67→  handler: (event: { payload: unknown }) => void,
 68→): Promise<UnlistenFn> {
 69→  if (!isTauriEnv) {
 70→    console.warn(`[Platform] Tauri listen called in non-Tauri environment: ${event}`);
 71→    return () => {};
 72→  }
 73→
 74→  const schema = (AppEventSchemaMap as Record<string, import("zod").ZodTypeAny>)[event];
 75→  if (!schema) {
 76→    // Unknown event (not in AppEventMap) — pass through without validation
 77→    return tauriListen(event, handler);
 78→  }
 79→
 80→  return tauriListen(event, (e) => {
 81→    const result = schema.safeParse(e.payload);
 82→    if (!result.success) {
 83→      console.error(
 84→        `[Platform] Event "${event}" payload failed schema validation:`,
 85→        result.error.format(),
 86→      );
 87→      // Still deliver the original payload so the app doesn't break —
 88→      // the console.error is enough to surface Rust↔TS drift during dev.
 89→      handler(e);
 90→      return;
 91→    }
 92→    // Pass validated + stripped payload (extra keys removed by Zod)
 93→    handler({ ...e, payload: result.data });
 94→  });
 95→}
 96→
 97→/**
 98→ * Emit a Tauri event (broadcasts to all windows)
 99→ */
100→export async function emit<T>(event: string, payload?: T): Promise<void> {
101→  if (!isTauriEnv) {
102→    console.warn(`[Platform] Tauri emit called in non-Tauri environment: ${event}`);
103→    return;
104→  }
105→
106→  return tauriEmit(event, payload);
107→}
108→
109→/**
110→ * Check if Tauri APIs are available
111→ */
112→export function isTauriAvailable(): boolean {
113→  return isTauriEnv;
114→}
