29→export function dbGetMessages(
30→  sessionId: string,
31→  opts?: { limit?: number; before?: number; after?: number }
32→): Promise<PaginatedMessages> {
33→  // Build payload without null fields — Tauri's serde can't deserialize
34→  // JSON null to Rust Option<i64>. Missing keys deserialize to None correctly.
35→  const payload: Record<string, unknown> = { session_id: sessionId };
36→  if (opts?.limit != null) payload.limit = opts.limit;
37→  if (opts?.before != null) payload.before = opts.before;
38→  if (opts?.after != null) payload.after = opts.after;
39→  return invoke<PaginatedMessages>("db_get_messages", payload);
40→}
