 18→/**
 19→ * Discriminated union for DB write outcomes.
 20→ * Replaces the old string|null pattern that silently swallowed failures.
 21→ */
 22→export type WriteResult<T = string> = { ok: true; value: T } | { ok: false; error: string };
 23→
 24→// ── Save Messages ────────────────────────────────────────────────────────
 25→
 26→/**
 27→ * Save an assistant message to the database.
 28→ * Called after FrontendClient.sendMessage() in the Claude handler.
 29→ */
 30→export function saveAssistantMessage(
 31→  sessionId: string,
 32→  message: { id?: string; role?: string; content?: unknown; stop_reason?: string },
 33→  model: string = "opus",
 34→  parentToolUseId: string | null = null
 35→): WriteResult {
 36→  const t0 = Date.now();
 37→  const db = getDatabase();
 38→  const messageId = uuidv7();
 39→  const sentAt = new Date().toISOString();
 40→
 41→  // Store flat content array for normal messages. For "cancelled" messages,
 42→  // write envelope so the frontend can detect cancellation from DB content
 43→  // (the "Turn interrupted" label in AssistantTurn needs this to survive page reload).
 44→  // Other stop_reasons (e.g. max_tokens) are communicated via session error events.
 45→  // Old DB rows may have envelope for any stop_reason — the frontend read shim
 46→  // in normalizeContentBlocks handles backward compat.
 47→  const contentPayload =
 48→    message.stop_reason === "cancelled"
 49→      ? { message: { stop_reason: "cancelled" }, blocks: message.content ?? [] }
 50→      : (message.content ?? []);
 51→  const content = JSON.stringify(contentPayload);
 52→
 53→  try {
 54→    const tInsert = Date.now();
 55→    db.prepare(
 56→      `
 57→      INSERT INTO messages (id, session_id, role, content, sent_at, model, agent_message_id, parent_tool_use_id)
 58→      VALUES (?, ?, 'assistant', ?, ?, ?, ?, ?)
 59→    `
 60→    ).run(messageId, sessionId, content, sentAt, model, message.id || null, parentToolUseId);
 61→    const insertMs = Date.now() - tInsert;
 62→
 63→    const tNotify = Date.now();
 64→    notifyBackend(NOTIFY_SESSION_MESSAGE, sessionId);
 65→    const notifyMs = Date.now() - tNotify;
 66→
 67→    const totalMs = Date.now() - t0;
 68→    if (totalMs > 10) {
 69→      console.log(
 70→        `[TIMING][SESSION-WRITER] saveAssistantMessage session=${sessionId} insert=${insertMs}ms notify=${notifyMs}ms total=${totalMs}ms`
 71→      );
 72→    }
 73→    return { ok: true, value: messageId };
 74→  } catch (error) {
 75→    const msg = getErrorMessage(error);
 76→    console.error(`[SESSION-WRITER] Failed to save assistant message:`, msg);
 77→    return { ok: false, error: msg };
 78→  }
 79→}
