 29→    let updated_at: String = row.get("updated_at")?;
 30→    let git_target_branch: Option<String> = row.get("git_target_branch")?;
 31→    let setup_status: Option<String> = row.get("setup_status")?;
 32→    let error_message: Option<String> = row.get("error_message")?;
 33→    let init_stage: Option<String> = row.get("init_stage")?;
 34→    let repo_name: Option<String> = row.get("repo_name")?;
 35→    let root_path: Option<String> = row.get("root_path")?;
 36→    let git_default_branch: Option<String> = row.get("git_default_branch")?;
 37→    let repo_sort_order: Option<i64> = row.get("repo_sort_order")?;
 38→    let session_status: Option<String> = row.get("session_status")?;
 39→    let model: Option<String> = row.get("model")?;
 40→    let latest_message_sent_at: Option<String> = row.get("latest_message_sent_at")?;
