 55→        updated_at,
 56→        git_target_branch,
 57→        setup_status,
 58→        error_message,
 59→        init_stage,
 60→        repo_name,
 61→        root_path,
 62→        git_default_branch,
 63→        repo_sort_order,
 64→        session_status,
 65→        model,
