 71→// ─── 1. db_get_workspaces_by_repo ───────────────────────────
 72→
 73→/// Fetch all workspaces grouped by repository.
 74→/// Replaces GET /workspaces/by-repo (polled every 10s from sidebar).
 75→/// Returns fully grouped RepoGroup[] — no post-processing in frontend.
 76→#[tauri::command]
 77→pub fn db_get_workspaces_by_repo(
 78→    state: Option<String>,
 79→    db: State<'_, DbManager>,
 80→) -> Result<Vec<RepoGroup>, String> {
 81→    db.with_conn(|conn| {
 82→        // Keep parity with backend/src/db/queries.ts:
 83→        // support comma-separated state filters (e.g. "ready,initializing").
 84→        let state_values = state
 85→            .as_deref()
 86→            .map(|raw| {
 87→                raw.split(',')
 88→                    .map(str::trim)
 89→                    .filter(|s| !s.is_empty())
 90→                    .map(str::to_string)
 91→                    .collect::<Vec<_>>()
 92→            })
 93→            .filter(|values| !values.is_empty());
 94→
 95→        let state_filter = state_values
 96→            .as_ref()
 97→            .map(|values| {
 98→                let placeholders = (1..=values.len())
 99→                    .map(|idx| format!("?{idx}"))
100→                    .collect::<Vec<_>>()
101→                    .join(",");
102→                format!("WHERE w.state IN ({placeholders})")
103→            })
104→            .unwrap_or_default();
105→
106→        let sql = format!(
107→            "SELECT
108→                w.id, w.repository_id, w.slug, w.title, w.git_branch, w.state,
109→                w.current_session_id, w.updated_at,
110→                w.git_target_branch, w.setup_status, w.error_message, w.init_stage,
111→                r.name as repo_name, r.sort_order as repo_sort_order, r.root_path,
112→                r.git_default_branch,
113→                s.status as session_status, s.model,
114→                s.last_user_message_at as latest_message_sent_at
115→            FROM workspaces w
116→            LEFT JOIN repositories r ON w.repository_id = r.id
117→            LEFT JOIN sessions s ON w.current_session_id = s.id
118→            {}
119→            ORDER BY r.sort_order, r.name, w.updated_at DESC",
120→            state_filter
121→        );
122→
123→        let mut stmt = conn.prepare(&sql)?;
124→
125→        let rows: Vec<WorkspaceWithDetails> = if let Some(ref values) = state_values {
126→            let params = rusqlite::params_from_iter(values.iter());
127→            let mapped = stmt.query_map(params, |row| read_workspace_row(row))?;
128→            mapped.collect::<Result<Vec<_>, _>>()?
129→        } else {
130→            let mapped = stmt.query_map([], |row| read_workspace_row(row))?;
131→            mapped.collect::<Result<Vec<_>, _>>()?
132→        };
133→
134→        // Group by repository_id, preserving insertion order (already sorted by SQL).
135→        // Uses Vec<RepoGroup> + position lookup to avoid adding indexmap dependency.
136→        let mut result: Vec<RepoGroup> = Vec::new();
137→        let mut repo_positions: std::collections::HashMap<String, usize> =
138→            std::collections::HashMap::new();
139→
140→        for ws in rows {
141→            let repo_id = ws.repository_id.clone();
142→            if let Some(&pos) = repo_positions.get(&repo_id) {
143→                result[pos].workspaces.push(ws);
144→            } else {
145→                let pos = result.len();
146→                repo_positions.insert(repo_id.clone(), pos);
