37→ * Fetch opendevs.json manifest for a repo.
38→ * staleTime: Infinity — manifest doesn't change unless user saves.
39→ */
40→export function useRepoManifest(repoId: string | null) {
41→  return useQuery({
42→    queryKey: queryKeys.repos.manifest(repoId || ""),
43→    queryFn: () => RepoService.fetchManifest(repoId!),
44→    enabled: !!repoId,
45→    staleTime: Infinity,
46→  });
47→}
