49→/**
50→ * Save opendevs.json manifest for a repo.
51→ * Invalidates the manifest query on success.
52→ */
53→export function useSaveRepoManifest() {
54→  const queryClient = useQueryClient();
55→
56→  return useMutation({
57→    mutationFn: ({ repoId, manifest }: { repoId: string; manifest: Record<string, unknown> }) =>
58→      RepoService.saveManifest(repoId, manifest),
59→    onSuccess: (_data, { repoId }) => {
60→      queryClient.invalidateQueries({ queryKey: queryKeys.repos.manifest(repoId) });
61→      // Also invalidate workspace manifests since they inherit from repo
62→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
63→    },
64→  });
65→}
66→
67→/**
68→ * Add repository mutation
69→ */
70→export function useAddRepo() {
71→  const queryClient = useQueryClient();
72→
73→  return useMutation({
74→    mutationFn: (rootPath: string) => RepoService.add(rootPath),
75→    onSuccess: (_data, rootPath) => {
76→      track("repo_added", { repo_name: rootPath.split("/").pop() });
77→      // Invalidate repos and workspaces (new repo means new potential workspaces)
78→      queryClient.invalidateQueries({ queryKey: queryKeys.repos.all });
79→      queryClient.invalidateQueries({ queryKey: queryKeys.workspaces.all });
80→    },
81→  });
